                '.filter-tab.filter-tab-live.filter-tab-active{background:linear-gradient(135deg,#0a8a3a 0%,#0f6f2e 100%);color:#fff;border-color:#5fd489;box-shadow:0 0 12px rgba(95,212,137,.35)}';
