// Helper: map roulette number to color
function _rouletteNumberColor(n) {
    if (n === 0) return 'green';
    var reds = [1,3,5,7,9,12,14,16,18,19,21,23,25,27,30,32,34,36];
    return reds.indexOf(n) !== -1 ? 'red' : 'black';
}

