// Sprint 171: Spin speed indicator (spins per minute)
var _spinTimestamps171 = [];
function _resetSpinSpeed() {
    _spinTimestamps171 = [];
    var el = document.getElementById('spinSpeedBadge');
    if (el) el.style.display = 'none';
}
function _updateSpinSpeed() {
    var now = Date.now();
    _spinTimestamps171.push(now);
    // Keep only last 60 seconds of timestamps
    var cutoff = now - 60000;
    while (_spinTimestamps171.length > 0 && _spinTimestamps171[0] < cutoff) {
        _spinTimestamps171.shift();
    }
    var el = document.getElementById('spinSpeedBadge');
    if (!el) return;
    var spm = _spinTimestamps171.length;
    if (spm < 2) { el.style.display = 'none'; return; }
    el.textContent = spm + ' spm';
    el.className = 'spin-speed-badge' + (spm >= 30 ? ' ssb-fast' : spm >= 15 ? ' ssb-med' : ' ssb-slow');
    el.style.display = '';
}

// Sprint 172: Hot/cold meter (rolling win rate vs expected ~35%)
var _hotColdTotal172 = 0; var _hotColdWins172 = 0; var _hotColdRecent172 = [];
function _resetHotCold() {
    _hotColdTotal172 = 0; _hotColdWins172 = 0; _hotColdRecent172 = [];
    var el = document.getElementById('hotColdMeter');
    if (el) el.style.display = 'none';
}
function _updateHotCold(won) {
    _hotColdRecent172.push(won ? 1 : 0);
    // Rolling window of last 30 spins
    if (_hotColdRecent172.length > 30) _hotColdRecent172.shift();
    var el = document.getElementById('hotColdMeter');
    if (!el || _hotColdRecent172.length < 5) { if (el) el.style.display = 'none'; return; }
    var wins = 0;
    for (var i = 0; i < _hotColdRecent172.length; i++) wins += _hotColdRecent172[i];
    var rate = wins / _hotColdRecent172.length;
    var pct = Math.round(rate * 100);
    var state = rate >= 0.50 ? 'ON FIRE' : rate >= 0.35 ? 'WARM' : rate >= 0.20 ? 'COOL' : 'ICE COLD';
    var cls = rate >= 0.50 ? 'hcm-fire' : rate >= 0.35 ? 'hcm-warm' : rate >= 0.20 ? 'hcm-cool' : 'hcm-ice';
    el.textContent = state + ' (' + pct + '%)';
    el.className = 'hot-cold-meter ' + cls;
    el.style.display = '';
}

// Sprint 173: Profit per minute tracker
var _profitStart173 = 0; var _profitNet173 = 0;
function _resetProfitPerMin() {
    _profitStart173 = Date.now();
    _profitNet173 = 0;
    var el = document.getElementById('profitPerMinBadge');
    if (el) el.style.display = 'none';
}
function _updateProfitPerMin(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    _profitNet173 += (winAmount || 0) - betAmount;
    var elapsed = (Date.now() - _profitStart173) / 60000;
    if (elapsed < 0.5) return;
    var ppm = _profitNet173 / elapsed;
    var el = document.getElementById('profitPerMinBadge');
    if (!el) return;
    var sign = ppm >= 0 ? '+' : '';
    el.textContent = sign + '$' + ppm.toFixed(2) + '/min';
    el.className = 'profit-per-min-badge' + (ppm >= 0 ? ' ppm-pos' : ' ppm-neg');
    el.style.display = '';
}

// Sprint 174: Balance high watermark
var _balanceHigh174 = 0; var _balanceStart174 = 0;
function _resetBalanceWatermark() {
    _balanceHigh174 = (typeof balance !== 'undefined') ? balance : 0;
    _balanceStart174 = _balanceHigh174;
    var el = document.getElementById('balanceWatermarkBadge');
    if (el) el.style.display = 'none';
}
function _updateBalanceWatermark() {
    var cur = (typeof balance !== 'undefined') ? balance : 0;
    if (cur > _balanceHigh174) _balanceHigh174 = cur;
    var el = document.getElementById('balanceWatermarkBadge');
    if (!el) return;
    var diff = _balanceHigh174 - _balanceStart174;
    if (diff <= 0) { el.style.display = 'none'; return; }
    el.textContent = 'Peak +$' + diff.toFixed(2);
    el.className = 'balance-watermark-badge bwb-up';
    el.style.display = '';
}

// Sprint 175: Near-miss counter
var _nearMissCount175 = 0;
function _resetNearMiss() {
    _nearMissCount175 = 0;
    var el = document.getElementById('nearMissBadge');
    if (el) el.style.display = 'none';
}
function _updateNearMiss(grid, won) {
    if (won || !grid || !grid.length) return;
    var row0 = [];
    for (var c = 0; c < grid.length; c++) {
        if (grid[c] && grid[c][0]) row0.push(grid[c][0]);
    }
    if (row0.length >= 3) {
        var match01 = row0[0] === row0[1];
        var match02 = row0[0] === row0[2];
        var match12 = row0[1] === row0[2];
        if ((match01 && !match02) || (match02 && !match01) || (match12 && !match01)) {
            _nearMissCount175++;
        }
    }
    var el = document.getElementById('nearMissBadge');
    if (!el) return;
    if (_nearMissCount175 >= 2) {
        el.textContent = _nearMissCount175 + ' near miss' + (_nearMissCount175 > 1 ? 'es' : '');
        el.style.display = '';
    }
}

// Sprint 176: Best win multiplier this session
var _bestMult176 = 0;
function _resetBestMultiplier() {
    _bestMult176 = 0;
    var el = document.getElementById('bestMultBadge');
    if (el) el.style.display = 'none';
}
function _updateBestMultiplier(winAmount, betAmount) {
    if (!winAmount || !betAmount || betAmount <= 0) return;
    var mult = winAmount / betAmount;
    if (mult <= 1) return;
    if (mult > _bestMult176) _bestMult176 = mult;
    var el = document.getElementById('bestMultBadge');
    if (!el) return;
    el.textContent = 'Best: ' + _bestMult176.toFixed(1) + 'x';
    var cls = _bestMult176 >= 50 ? ' bm-epic' : _bestMult176 >= 10 ? ' bm-great' : ' bm-good';
    el.className = 'best-mult-badge' + cls;
    el.style.display = '';
}

// Sprint 177: Session timer
var _sessionStart177 = 0;
var _sessionTimerInterval177 = null;
function _resetSessionTimer() {
    _sessionStart177 = Date.now();
    var el = document.getElementById('sessionTimerBadge');
    if (el) { el.textContent = '0:00'; el.style.display = ''; }
    if (_sessionTimerInterval177) clearInterval(_sessionTimerInterval177);
    _sessionTimerInterval177 = setInterval(function() {
        var elapsed = Math.floor((Date.now() - _sessionStart177) / 1000);
        var mins = Math.floor(elapsed / 60);
        var secs = elapsed % 60;
        var el2 = document.getElementById('sessionTimerBadge');
        if (el2) el2.textContent = mins + ':' + (secs < 10 ? '0' : '') + secs;
    }, 1000);
}

// Sprint 178: Volatility indicator (std dev of recent results)
var _volResults178 = [];
function _resetVolatility() {
    _volResults178 = [];
    var el = document.getElementById('volatilityBadge');
    if (el) el.style.display = 'none';
}
function _updateVolatility(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    var mult = (winAmount || 0) / betAmount;
    _volResults178.push(mult);
    if (_volResults178.length > 20) _volResults178.shift();
    if (_volResults178.length < 5) return;
    var sum = 0;
    for (var i = 0; i < _volResults178.length; i++) sum += _volResults178[i];
    var mean = sum / _volResults178.length;
    var sqDiffSum = 0;
    for (var j = 0; j < _volResults178.length; j++) {
        var d = _volResults178[j] - mean;
        sqDiffSum += d * d;
    }
    var stdDev = Math.sqrt(sqDiffSum / _volResults178.length);
    var el = document.getElementById('volatilityBadge');
    if (!el) return;
    var label = stdDev >= 3 ? 'HIGH VOL' : stdDev >= 1 ? 'MED VOL' : 'LOW VOL';
    var cls = stdDev >= 3 ? 'vol-high' : stdDev >= 1 ? 'vol-med' : 'vol-low';
    el.textContent = label;
    el.className = 'volatility-badge ' + cls;
    el.style.display = '';
}


