    for (var i = 0; i < _payoutHist188.length; i++) {
        if (_payoutHist188[i] > maxMult) maxMult = _payoutHist188[i];
    }
    if (maxMult < 0.1) maxMult = 1;
    var bars = '';
    for (var j = 0; j < _payoutHist188.length; j++) {
        var h = Math.max(2, Math.round((_payoutHist188[j] / maxMult) * 16));
        var color = _payoutHist188[j] >= 2 ? '#00ff88' : _payoutHist188[j] >= 1 ? '#fdcb6e' : '#636e72';
        bars += '<span style="display:inline-block;width:3px;height:' + h + 'px;background:' + color + ';border-radius:1px;vertical-align:bottom;margin:0 1px;"></span>';
    }
    el.innerHTML = bars;
