// Sprint 189: Session P&L sparkline (tiny inline chart of balance over time)
var _plHistory189 = [];
function _resetPlSpark() {
    _plHistory189 = [];
    var el = document.getElementById('plSparkline');
    if (el) el.style.display = 'none';
}
function _updatePlSpark() {
    var cur = (typeof balance !== 'undefined') ? balance : 0;
    _plHistory189.push(cur);
    if (_plHistory189.length > 20) _plHistory189.shift();
    var el = document.getElementById('plSparkline');
    if (!el || _plHistory189.length < 3) { if (el) el.style.display = 'none'; return; }
    var minV = _plHistory189[0]; var maxV = _plHistory189[0];
    for (var i = 1; i < _plHistory189.length; i++) {
        if (_plHistory189[i] < minV) minV = _plHistory189[i];
        if (_plHistory189[i] > maxV) maxV = _plHistory189[i];
    }
    var range = maxV - minV;
    if (range < 1) range = 1;
    var points = '';
    for (var j = 0; j < _plHistory189.length; j++) {
        var x = Math.round((j / (_plHistory189.length - 1)) * 50);
        var y = 16 - Math.round(((_plHistory189[j] - minV) / range) * 14);
        points += (j === 0 ? 'M' : 'L') + x + ',' + y;
    }
    var color = _plHistory189[_plHistory189.length - 1] >= _plHistory189[0] ? '#00ff88' : '#ff7675';
    el.innerHTML = '<svg width="52" height="18" viewBox="0 0 52 18"><path d="' + points + '" fill="none" stroke="' + color + '" stroke-width="1.5" stroke-linecap="round"/></svg>';
    el.style.display = '';
}

// Sprint 190: Bet tier progress bar (progress to next bet tier)
function _resetBetTierProgress() {
    var el = document.getElementById('betTierProgress');
    if (el) el.style.display = 'none';
}
function _updateBetTierProgress() {
    if (typeof BET_TIERS === 'undefined' || typeof currentBet === 'undefined') return;
    var el = document.getElementById('betTierProgress');
    if (!el) return;
    var currentTier = null; var nextTier = null;
    for (var i = 0; i < BET_TIERS.length; i++) {
        if (currentBet >= BET_TIERS[i].min) { currentTier = BET_TIERS[i]; break; }
    }
    // Find next higher tier
    for (var j = BET_TIERS.length - 1; j >= 0; j--) {
        if (BET_TIERS[j].min > currentBet) { nextTier = BET_TIERS[j]; }
    }
    if (!currentTier || !nextTier) { el.style.display = 'none'; return; }
    var prevMin = currentTier.min;
    var pct = Math.round(((currentBet - prevMin) / (nextTier.min - prevMin)) * 100);
    pct = Math.min(Math.max(pct, 0), 100);
    el.innerHTML = '<span class="btp-label">' + currentTier.label + '</span>' +
        '<span class="btp-bar"><span class="btp-fill" style="width:' + pct + '%"></span></span>' +
        '<span class="btp-next">' + nextTier.label + '</span>';
    el.style.display = '';
}

