// Sprint 206: Bet efficiency (cumulative return per dollar wagered)
var _effWagered206 = 0; var _effReturned206 = 0;
function _resetBetEfficiency() {
    _effWagered206 = 0; _effReturned206 = 0;
    var el = document.getElementById('betEfficiencyBadge');
    if (el) el.style.display = 'none';
}
function _updateBetEfficiency(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    _effWagered206 += betAmount;
    _effReturned206 += (winAmount || 0);
    if (_effWagered206 < 10) return;
    var eff = _effReturned206 / _effWagered206;
    var el = document.getElementById('betEfficiencyBadge');
    if (!el) return;
    el.textContent = (eff * 100).toFixed(1) + '% return';
    el.className = 'bet-efficiency-badge' + (eff >= 1 ? ' bef-profit' : eff >= 0.85 ? ' bef-even' : ' bef-loss');
    el.style.display = '';
}

// Sprint 207: Session summary (auto-saves to localStorage on each spin)
var _sessionSummary207 = {};
function _resetSessionSummary() {
    _sessionSummary207 = {
        gameId: (typeof currentGame !== 'undefined' && currentGame) ? currentGame.id : 'unknown',
        startBalance: (typeof balance !== 'undefined') ? balance : 0,
        startTime: Date.now(),
        spins: 0, wins: 0, totalWagered: 0, totalWon: 0, biggestWin: 0
    };
}
function _updateSessionSummary(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    _sessionSummary207.spins++;
    _sessionSummary207.totalWagered += betAmount;
    _sessionSummary207.totalWon += (winAmount || 0);
    if (winAmount > 0) _sessionSummary207.wins++;
    if (winAmount > _sessionSummary207.biggestWin) _sessionSummary207.biggestWin = winAmount;
    _sessionSummary207.endBalance = (typeof balance !== 'undefined') ? balance : 0;
    _sessionSummary207.duration = Math.round((Date.now() - _sessionSummary207.startTime) / 1000);
    try {
        localStorage.setItem('casino_last_session', JSON.stringify(_sessionSummary207));
    } catch(e) {}
}

// Sprint 208: Spin rhythm indicator (consistency of spin timing)
var _rhythmGaps208 = [];
var _rhythmLast208 = 0;
function _resetSpinRhythm() {
    _rhythmGaps208 = []; _rhythmLast208 = 0;
    var el = document.getElementById('spinRhythmBadge');
    if (el) el.style.display = 'none';
}
function _updateSpinRhythm() {
    var now = Date.now();
    if (_rhythmLast208 > 0) {
        var gap = now - _rhythmLast208;
        _rhythmGaps208.push(gap);
        if (_rhythmGaps208.length > 10) _rhythmGaps208.shift();
    }
    _rhythmLast208 = now;
    if (_rhythmGaps208.length < 4) return;
    // Calculate coefficient of variation
    var sum = 0;
    for (var i = 0; i < _rhythmGaps208.length; i++) sum += _rhythmGaps208[i];
    var mean = sum / _rhythmGaps208.length;
    var sqSum = 0;
    for (var j = 0; j < _rhythmGaps208.length; j++) {
        var d = _rhythmGaps208[j] - mean;
        sqSum += d * d;
    }
    var cv = Math.sqrt(sqSum / _rhythmGaps208.length) / mean;
    var el = document.getElementById('spinRhythmBadge');
    if (!el) return;
    var label, cls;
    if (cv < 0.3) { label = '\u{1F3B5} Steady'; cls = 'srh-steady'; }
    else if (cv < 0.7) { label = '\u{1F3B6} Mixed'; cls = 'srh-mixed'; }
    else { label = '\u26A1 Erratic'; cls = 'srh-erratic'; }
    el.textContent = label;
    el.className = 'spin-rhythm-badge ' + cls;
    el.style.display = '';
}

// Sprint 209: Max exposure tracker (biggest bet relative to balance)
var _maxExposure209 = 0;
function _resetMaxExposure() {
    _maxExposure209 = 0;
    var el = document.getElementById('maxExposureBadge');
    if (el) el.style.display = 'none';
}
function _updateMaxExposure(betAmount) {
    if (!betAmount || betAmount <= 0) return;
    var bal = (typeof balance !== 'undefined') ? balance : 0;
    if (bal <= 0) return;
    var exposure = (betAmount / bal) * 100;
    if (exposure > _maxExposure209) _maxExposure209 = exposure;
    var el = document.getElementById('maxExposureBadge');
    if (!el) return;
    if (_maxExposure209 >= 2) {
        el.textContent = 'Max risk: ' + _maxExposure209.toFixed(1) + '%';
        el.className = 'max-exposure-badge' + (_maxExposure209 >= 20 ? ' meb-danger' : _maxExposure209 >= 10 ? ' meb-warn' : ' meb-safe');
        el.style.display = '';
    }
}

