// Sprint 211: Bet history mini-feed (last 5 spins with results inline)
var _betHistory211 = [];
function _resetBetHistory() {
    _betHistory211 = [];
    var el = document.getElementById('betHistoryFeed');
    if (el) { el.innerHTML = ''; el.style.display = 'none'; }
}
function _updateBetHistory(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    var won = (winAmount || 0) > 0;
    var mult = won ? ((winAmount / betAmount)).toFixed(1) : '0';
    _betHistory211.push({ bet: betAmount, win: winAmount || 0, mult: mult, won: won });
    if (_betHistory211.length > 5) _betHistory211.shift();
    var el = document.getElementById('betHistoryFeed');
    if (!el) return;
    var html = '';
    for (var i = _betHistory211.length - 1; i >= 0; i--) {
        var h = _betHistory211[i];
        var cls = h.won ? 'bhf-win' : 'bhf-loss';
        html += '<span class="bhf-entry ' + cls + '">$' + h.bet.toFixed(0) + '\u2192' + h.mult + 'x</span>';
    }
    el.innerHTML = html;
    el.style.display = '';
}

// Sprint 212: Symbol pay peek (shows top 3 paying symbols for current game)
function _resetSymbolPayPeek() {
    var el = document.getElementById('symbolPayPeek');
    if (!el) return;
    if (typeof currentGame === 'undefined' || !currentGame || !currentGame.symbols || !currentGame.payTable) {
        el.style.display = 'none';
        return;
    }
    var payTable = currentGame.payTable;
    var symbols = currentGame.symbols;
    // Sort symbols by pay value (triple match)
    var payRanked = [];
    for (var i = 0; i < symbols.length; i++) {
        var sym = symbols[i];
        var pay = 0;
        if (payTable[sym]) {
            // payTable[sym] can be a number or array (for different match counts)
            if (typeof payTable[sym] === 'number') pay = payTable[sym];
            else if (Array.isArray(payTable[sym])) pay = payTable[sym][payTable[sym].length - 1] || 0;
            else if (typeof payTable[sym] === 'object' && payTable[sym][3]) pay = payTable[sym][3];
        }
        payRanked.push({ sym: sym, pay: pay });
    }
    payRanked.sort(function(a, b) { return b.pay - a.pay; });
    var top3 = payRanked.slice(0, 3);
    var html = '';
    for (var j = 0; j < top3.length; j++) {
        html += '<span class="spp-item">' + top3[j].sym.slice(0, 6) + ':' + top3[j].pay + 'x</span>';
    }
    if (html) {
        el.innerHTML = '<span class="spp-label">Top pays</span>' + html;
        el.style.display = '';
    } else {
        el.style.display = 'none';
    }
}

// Sprint 213: Mini jackpot pool (1% of each bet accumulates, random trigger)
var _miniJackpot213 = 0; var _miniJackpotWins213 = 0;
function _resetMiniJackpot() {
    _miniJackpot213 = 0; _miniJackpotWins213 = 0;
    var el = document.getElementById('miniJackpotBadge');
    if (el) { el.textContent = 'Mini JP: $0.00'; el.className = 'mini-jackpot-badge'; el.style.display = ''; }
}
function _updateMiniJackpot(betAmount) {
    if (!betAmount || betAmount <= 0) return;
    _miniJackpot213 += betAmount * 0.01; // 1% contribution
    var el = document.getElementById('miniJackpotBadge');
    if (!el) return;
    // Random trigger: 0.5% chance per spin when pool > $1
    if (_miniJackpot213 >= 1 && Math.random() < 0.005) {
        var winAmt = _miniJackpot213;
        _miniJackpotWins213++;
        // Award to balance
        if (typeof balance !== 'undefined') balance += winAmt;
        if (typeof updateBalance === 'function') updateBalance();
        el.textContent = '\u{1F389} MINI JP WON: $' + winAmt.toFixed(2) + '!';
        el.className = 'mini-jackpot-badge mjp-won';
        _miniJackpot213 = 0;
        setTimeout(function() {
            el.textContent = 'Mini JP: $0.00';
            el.className = 'mini-jackpot-badge';
        }, 4000);
    } else {
        el.textContent = 'Mini JP: $' + _miniJackpot213.toFixed(2);
        el.className = 'mini-jackpot-badge' + (_miniJackpot213 >= 10 ? ' mjp-high' : _miniJackpot213 >= 5 ? ' mjp-mid' : '');
    }
    el.style.display = '';
}

