// Sprint 218: Lucky number tracker (tracks which spin numbers land wins)
var _luckyNums218 = []; var _totalSpins218 = 0;
function _resetLuckyNumber() {
    _luckyNums218 = []; _totalSpins218 = 0;
    var el = document.getElementById('luckyNumberBadge');
    if (el) el.style.display = 'none';
}
function _updateLuckyNumber(won) {
    _totalSpins218++;
    if (won) _luckyNums218.push(_totalSpins218);
    if (_luckyNums218.length < 3) return;
    // Find most common last digit of winning spins
    var digitCounts = {};
    for (var i = 0; i < _luckyNums218.length; i++) {
        var d = _luckyNums218[i] % 10;
        digitCounts[d] = (digitCounts[d] || 0) + 1;
    }
    var bestDigit = 0; var bestCount = 0;
    for (var k in digitCounts) {
        if (digitCounts[k] > bestCount) { bestCount = digitCounts[k]; bestDigit = k; }
    }
    var el = document.getElementById('luckyNumberBadge');
    if (!el) return;
    el.textContent = 'Lucky #' + bestDigit + ' (' + bestCount + ' wins)';
    el.style.display = '';
}


