// Sprint 256 — Multiplier history graph (sparkline)
var _multHistory256 = [];
function _resetMultHistory() {
    _multHistory256 = [];
    var el = document.getElementById('multGraphCanvas');
    if (el) { el.getContext('2d').clearRect(0, 0, el.width, el.height); }
}
function _addMultiplier(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) { _multHistory256.push(0); }
    else { _multHistory256.push((winAmount || 0) / betAmount); }
    if (_multHistory256.length > 20) _multHistory256.shift();
    _drawMultSparkline();
}
function _drawMultSparkline() {
    var canvas = document.getElementById('multGraphCanvas');
    if (!canvas) return;
    var ctx = canvas.getContext('2d');
    var w = canvas.width; var h = canvas.height;
    ctx.clearRect(0, 0, w, h);
    if (_multHistory256.length < 2) return;
    var max = Math.max.apply(null, _multHistory256);
    if (max < 1) max = 1;
    ctx.strokeStyle = '#7fbaec';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    _multHistory256.forEach(function(val, i) {
        var x = (i / (_multHistory256.length - 1)) * w;
        var y = h - (val / max) * (h - 4) - 2;
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
    });
    ctx.stroke();
    // Draw 1x reference line
    var refY = h - (1 / max) * (h - 4) - 2;
    ctx.strokeStyle = 'rgba(255,255,255,0.15)';
    ctx.setLineDash([3, 3]);
    ctx.beginPath();
    ctx.moveTo(0, refY);
    ctx.lineTo(w, refY);
    ctx.stroke();
    ctx.setLineDash([]);
}

