function _isFavorite(gameName) {
    return window._favorites257 && window._favorites257.indexOf(gameName) >= 0;
}
function _updateFavoriteStar(gameName) {
    // Update star icon on game cards if visible
    var cards = document.querySelectorAll('.game-card');
    cards.forEach(function(card) {
        var name = card.getAttribute('data-game');
        var star = card.querySelector('.fav-star');
        if (star && name) {
            star.textContent = _isFavorite(name) ? '\u2605' : '\u2606';
            star.className = 'fav-star' + (_isFavorite(name) ? ' fav-active' : '');
        }
    });
}

// Sprint 258 — Game search & filter
function _initGameSearch() {
    var input = document.getElementById('gameSearchInput');
    if (!input) return;
    input.addEventListener('input', function() {
        var query = input.value.toLowerCase().trim();
        var cards = document.querySelectorAll('.game-card');
        cards.forEach(function(card) {
            var name = (card.getAttribute('data-game') || '').toLowerCase();
            var provider = (card.getAttribute('data-provider') || '').toLowerCase();
            if (!query || name.indexOf(query) >= 0 || provider.indexOf(query) >= 0) {
                card.style.display = '';
            } else {
                card.style.display = 'none';
            }
        });
    });
}
function _filterByCategory(category) {
    var cards = document.querySelectorAll('.game-card');
    cards.forEach(function(card) {
        if (category === 'all') { card.style.display = ''; return; }
        if (category === 'favorites') {
            card.style.display = _isFavorite(card.getAttribute('data-game')) ? '' : 'none';
            return;
        }
        var cat = card.getAttribute('data-category') || '';
        card.style.display = (cat === category) ? '' : 'none';
    });
}


