// Mobile & Performance

// Sprint 259 — Touch gesture support
var _touch259 = { startX: 0, startY: 0, startTime: 0 };
function _initTouchGestures() {
    var gameArea = document.getElementById('slotGameContainer') || document.getElementById('gameArea') || document.body;
    gameArea.addEventListener('touchstart', function(e) {
        _touch259.startX = e.touches[0].clientX;
        _touch259.startY = e.touches[0].clientY;
        _touch259.startTime = Date.now();
    }, { passive: true });
    gameArea.addEventListener('touchend', function(e) {
        var dx = e.changedTouches[0].clientX - _touch259.startX;
        var dy = e.changedTouches[0].clientY - _touch259.startY;
        var dt = Date.now() - _touch259.startTime;
        if (dt > 500) return; // Too slow
        var absDx = Math.abs(dx);
        var absDy = Math.abs(dy);
        // Swipe up = spin
        if (absDy > 60 && dy < 0 && absDy > absDx * 1.5) {
            var spinBtn = document.getElementById('spinButton') || document.querySelector('.spin-btn');
            if (spinBtn && !spinning) spinBtn.click();
        }
        // Swipe left/right = change bet
        if (absDx > 60 && absDx > absDy * 1.5) {
            if (dx > 0) {
                var incBtn = document.getElementById('betIncrease') || document.querySelector('.bet-increase');
                if (incBtn) incBtn.click();
            } else {
                var decBtn = document.getElementById('betDecrease') || document.querySelector('.bet-decrease');
                if (decBtn) decBtn.click();
            }
        }
    }, { passive: true });
}

