// Sprint 286 — Win celebration animations
function _celebrateWin(multiplier) {
    if (multiplier < 2) return;
    var container = document.getElementById('celebrationContainer');
    if (!container) return;
    container.style.display = '';
    var count = multiplier >= 50 ? 100 : multiplier >= 10 ? 60 : 30;
    var colors = ['#ffd700', '#ff6b6b', '#7fec7f', '#7fbaec', '#c0a0ff', '#ff69b4'];
    for (var i = 0; i < count; i++) {
        (function(delay) {
            setTimeout(function() {
                var particle = document.createElement('div');
                particle.className = 'confetti-particle';
                particle.style.left = Math.random() * 100 + '%';
                particle.style.backgroundColor = colors[Math.floor(Math.random() * colors.length)];
                particle.style.animationDuration = (Math.random() * 2 + 1) + 's';
                particle.style.animationDelay = '0s';
                container.appendChild(particle);
                setTimeout(function() { if (particle.parentNode) particle.parentNode.removeChild(particle); }, 3000);
            }, delay);
        })(i * 30);
    }
    // Add win text
    if (multiplier >= 10) {
        var text = document.createElement('div');
        text.className = 'win-text-overlay';
        text.textContent = multiplier >= 50 ? 'MEGA WIN!' : multiplier >= 20 ? 'SUPER WIN!' : 'BIG WIN!';
        container.appendChild(text);
        setTimeout(function() { if (text.parentNode) text.parentNode.removeChild(text); }, 3000);
    }
    setTimeout(function() { container.style.display = 'none'; }, 4000);
}

