// Sprint 291-298 — Report spins to server for admin analytics
var _serverReport298 = { spinsSinceReport: 0, reportInterval: 10 };
function _reportSpinToServer(winAmount, betAmount) {
    _serverReport298.spinsSinceReport++;
    if (_serverReport298.spinsSinceReport < _serverReport298.reportInterval) return;
    _serverReport298.spinsSinceReport = 0;
    var game = (typeof currentGame !== 'undefined') ? currentGame : 'unknown';
    try {
        var xhr = new XMLHttpRequest();
        xhr.open('POST', '/api/admin/record-spin', true);
        xhr.setRequestHeader('Content-Type', 'application/json');
        xhr.send(JSON.stringify({
            betAmount: betAmount || 0,
            winAmount: winAmount || 0,
            gameId: game,
            userId: _session278 ? _session278.token.slice(0, 16) : 'anon'
        }));
    } catch(e) { /* Silent fail - analytics is non-critical */ }
}

// Report deposits to server
function _reportDepositToServer(amount, method) {
    try {
        var xhr = new XMLHttpRequest();
        xhr.open('POST', '/api/admin/record-deposit', true);
        xhr.setRequestHeader('Content-Type', 'application/json');
        xhr.send(JSON.stringify({
            amount: amount,
            method: method || 'unknown',
            userId: _session278 ? _session278.token.slice(0, 16) : 'anon'
        }));
    } catch(e) {}
}

