// Sprint 303 — VIP Progress Meter
var _vipTiers = [
    { name: 'Bronze', minWager: 0, color: '#CD7F32', bonus: 0 },
    { name: 'Silver', minWager: 500, color: '#C0C0C0', bonus: 2 },
    { name: 'Gold', minWager: 2500, color: '#FFD700', bonus: 5 },
    { name: 'Platinum', minWager: 10000, color: '#E5E4E2', bonus: 8 },
    { name: 'Diamond', minWager: 50000, color: '#B9F2FF', bonus: 12 }
];
function _getVipTier() {
    var w = (typeof totalWagered !== 'undefined') ? totalWagered : 0;
    for (var i = _vipTiers.length - 1; i >= 0; i--) { if (w >= _vipTiers[i].minWager) return _vipTiers[i]; }
    return _vipTiers[0];
}
function _updateVipMeter() {
    var el = document.getElementById('vipMeterBar');
    var label = document.getElementById('vipMeterLabel');
    if (!el || !label) return;
    var w = (typeof totalWagered !== 'undefined') ? totalWagered : 0;
    var t = _getVipTier(), idx = _vipTiers.indexOf(t);
    var next = _vipTiers[Math.min(idx + 1, _vipTiers.length - 1)];
    var pct = idx >= _vipTiers.length - 1 ? 100 : Math.min(100, ((w - t.minWager) / (next.minWager - t.minWager)) * 100);
    el.style.width = pct.toFixed(1) + '%';
    el.style.background = t.color;
    label.textContent = t.name;
    label.style.color = t.color;
}


