// Sprint 307 — Hot/Cold Game Indicator
var _gameHeatMap = {};
function _updateGameHeat(gameId, isWin) {
    if (!_gameHeatMap[gameId]) _gameHeatMap[gameId] = { wins: 0, spins: 0 };
    _gameHeatMap[gameId].spins++;
    if (isWin) _gameHeatMap[gameId].wins++;
    _renderGameHeat(gameId);
}
function _renderGameHeat(gameId) {
    var data = _gameHeatMap[gameId];
    if (!data || data.spins < 5) return;
    var rate = data.wins / data.spins;
    var el = document.getElementById('gameHeatBadge');
    if (!el) return;
    if (rate > 0.4) { el.textContent = 'HOT'; el.className = 'game-heat-badge game-heat-hot'; el.style.display = 'inline-block'; }
    else if (rate < 0.2) { el.textContent = 'COLD'; el.className = 'game-heat-badge game-heat-cold'; el.style.display = 'inline-block'; }
    else { el.style.display = 'none'; }
}


