// Sprint 310 — Auto-Spin Controls
var _autoSpinActive = false;
var _autoSpinRemaining = 0;
var _autoSpinLossLimit = 0;
var _autoSpinSessionLoss = 0;
function _startAutoSpin(count, lossLimit) {
    _autoSpinActive = true;
    _autoSpinRemaining = count;
    _autoSpinLossLimit = lossLimit || Infinity;
    _autoSpinSessionLoss = 0;
    _updateAutoSpinUI();
    _doAutoSpin();
}
function _stopAutoSpin() {
    _autoSpinActive = false;
    _autoSpinRemaining = 0;
    _updateAutoSpinUI();
}
function _doAutoSpin() {
    if (!_autoSpinActive || _autoSpinRemaining <= 0) { _stopAutoSpin(); return; }
    if (_autoSpinSessionLoss >= _autoSpinLossLimit) { _stopAutoSpin(); showNotification('Auto-spin stopped: loss limit reached', 'warning'); return; }
    _autoSpinRemaining--;
    if (typeof spin === 'function') spin();
    _updateAutoSpinUI();
}
function _onAutoSpinResult(won, amount) {
    if (!_autoSpinActive) return;
    if (!won) _autoSpinSessionLoss += amount;
    _updateAutoSpinUI();
    setTimeout(_doAutoSpin, 1500);
}
function _updateAutoSpinUI() {
    var btn = document.getElementById('autoSpinBtn');
    var counter = document.getElementById('autoSpinCounter');
    if (btn) btn.textContent = _autoSpinActive ? 'Stop Auto' : 'Auto Spin';
    if (btn) btn.className = _autoSpinActive ? 'autospin-btn autospin-active' : 'autospin-btn';
    if (counter) counter.textContent = _autoSpinActive ? _autoSpinRemaining + ' left' : '';
}


