    var html = '<div class="rg314-card"><h3>Self-Assessment</h3><p>Answer honestly:</p>';
    _rgQuestions.forEach(function(q, i) {
        html += '<div class="rg314-q"><span>' + (i+1) + '. ' + q + '</span>' +
            '<label><input type="radio" name="rg' + i + '" value="yes"> Yes</label>' +
            '<label><input type="radio" name="rg' + i + '" value="no"> No</label></div>';
    });
    html += '<button class="rg314-submit" onclick="_evaluateRG()">See Results</button>';
    html += '<button class="rg314-close" onclick="document.getElementById(&quot;rgAssessment314&quot;).style.display=&quot;none&quot;">Close</button></div>';
    overlay.innerHTML = html;
