/* ── 339-346 — geo-ip country detection ───────────────────────── */
var _geoCountry = 'US';
function _initGeoDetection() {
    fetch('https://ipapi.co/json/')
        .then(function(r) { return r.json(); })
        .then(function(d) {
            if (d && d.country_code) {
                _geoCountry = d.country_code;
                console.log('[Geo] Detected country:', _geoCountry);
                var flag = document.getElementById('geoFlag');
                if (flag) flag.textContent = _countryFlag(_geoCountry);
                _checkGeoRestrictions(_geoCountry);
            }
        })
        .catch(function(e) { console.warn('[Geo] Detection failed:', e); });
}
function _countryFlag(cc) {
    var base = 127397;
    return String.fromCodePoint(cc.charCodeAt(0) + base, cc.charCodeAt(1) + base);
}
function _checkGeoRestrictions(cc) {
    var restricted = ['US','AU','GB','FR','IT','ES','TR','SG','HK'];
    var el = document.getElementById('geoRestrictionBanner');
    if (!el) return;
    if (restricted.indexOf(cc) !== -1) {
        el.style.display = 'block';
        el.innerHTML = '<span style="color:#f0ad4e;">&#9888;</span> Gambling regulations may apply in your region (' + cc + '). Please verify local laws before playing.';
    }
}


/* ── 339-346 — age gate verification ──────────────────────────── */
