/* ── 339-346 — terms of service acceptance ────────────────────── */
var _tosAccepted = false;
function _checkTosAcceptance() {
    if (localStorage.getItem('ms_tos_accepted') === 'true') {
        _tosAccepted = true;
        return;
    }
    var modal = document.createElement('div');
    modal.id = 'tosModal';
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.9);z-index:99998;display:flex;align-items:center;justify-content:center;';
    modal.innerHTML = '<div style="background:#1a1a2e;border:2px solid #ffd700;border-radius:16px;padding:32px;max-width:500px;max-height:80vh;overflow-y:auto;">' +
        '<h2 style="color:#ffd700;margin:0 0 16px;">Terms of Service</h2>' +
        '<div style="color:#ccc;font-size:13px;line-height:1.6;max-height:300px;overflow-y:auto;margin-bottom:20px;padding:12px;background:#111;border-radius:8px;">' +
        '<p><strong>1. Eligibility:</strong> You must be 18+ and in a jurisdiction where online gambling is permitted.</p>' +
        '<p><strong>2. Fair Play:</strong> All games use certified RNG. House edge is disclosed per game.</p>' +
        '<p><strong>3. Responsible Gambling:</strong> Set deposit limits. Self-exclude if needed. We provide tools to help.</p>' +
        '<p><strong>4. Withdrawals:</strong> Processed within 48 hours. KYC verification required for amounts over $500.</p>' +
        '<p><strong>5. Privacy:</strong> Your data is encrypted and never sold to third parties.</p>' +
        '<p><strong>6. Disputes:</strong> Contact support@msaart.online for resolution.</p>' +
        '</div>' +
        '<label style="color:#ccc;display:flex;align-items:center;gap:8px;margin-bottom:16px;cursor:pointer;">' +
        '<input type="checkbox" id="tosCheckbox"> I have read and agree to the Terms of Service</label>' +
        '<button id="tosAcceptBtn" disabled style="background:#555;color:#999;border:none;padding:12px 32px;border-radius:8px;font-weight:bold;cursor:not-allowed;width:100%;font-size:15px;">Accept & Continue</button>' +
        '</div>';
    document.body.appendChild(modal);
    var cb = document.getElementById('tosCheckbox');
    var btn = document.getElementById('tosAcceptBtn');
    cb.onchange = function() {
        btn.disabled = !cb.checked;
        btn.style.background = cb.checked ? '#ffd700' : '#555';
        btn.style.color = cb.checked ? '#000' : '#999';
        btn.style.cursor = cb.checked ? 'pointer' : 'not-allowed';
    };
    btn.onclick = function() {
        if (!cb.checked) return;
        _tosAccepted = true;
        localStorage.setItem('ms_tos_accepted', 'true');
        modal.remove();
    };
}


/* ── 339-346 — responsible gambling footer ────────────────────── */
function _initRGFooter() {
    var existing = document.getElementById('rgFooter');
    if (existing) return;
    var footer = document.createElement('div');
    footer.id = 'rgFooter';
    footer.className = 'rg-footer';
    footer.innerHTML = '<div class="rg-footer-inner">' +
        '<span class="rg-footer-logo">18+</span>' +
        '<span class="rg-footer-sep">|</span>' +
        '<a href="https://www.begambleaware.org" target="_blank" rel="noopener" class="rg-footer-link">BeGambleAware</a>' +
        '<span class="rg-footer-sep">|</span>' +
        '<a href="https://www.gamcare.org.uk" target="_blank" rel="noopener" class="rg-footer-link">GamCare</a>' +
        '<span class="rg-footer-sep">|</span>' +
        '<a href="https://www.gamblingtherapy.org" target="_blank" rel="noopener" class="rg-footer-link">Gambling Therapy</a>' +
        '<span class="rg-footer-sep">|</span>' +
        '<a href="#" onclick="_openSelfExclude();return false;" class="rg-footer-link">Self-Exclude</a>' +
        '<span class="rg-footer-sep">|</span>' +
        '<a href="#" onclick="_openDepositLimits();return false;" class="rg-footer-link">Deposit Limits</a>' +
        '<span class="rg-footer-sep">|</span>' +
        '<span class="rg-footer-text">Gambling can be addictive. Play responsibly.</span>' +
        '</div>';
    document.body.appendChild(footer);
}
function _openSelfExclude() {
    if (confirm('Self-exclusion will lock your account for 6 months. Are you sure?')) {
        localStorage.setItem('ms_self_excluded', Date.now().toString());
        alert('You have been self-excluded for 6 months. Your account is now locked.');
        window.location.href = 'https://www.google.com';
    }
}
function _openDepositLimits() {
    var current = localStorage.getItem('ms_deposit_limit') || 'none';
    var limit = prompt('Set your daily deposit limit (USD). Current: ' + current + '\nEnter amount or "none" to remove:');
    if (limit !== null) {
        if (limit === 'none' || limit === '') {
            localStorage.removeItem('ms_deposit_limit');
            alert('Deposit limit removed.');
        } else {
            var val = parseFloat(limit);
            if (!isNaN(val) && val > 0) {
                localStorage.setItem('ms_deposit_limit', val.toString());
                alert('Daily deposit limit set to $' + val.toFixed(2));
            }
        }
    }
}


// Sprint 339 — Stripe Checkout Integration UI
function _openStripeDeposit(amount) {
    var el = document.getElementById('stripeCheckout339');
    if (!el) return;
    el.querySelector('.sc339-amount').textContent = '$' + amount.toFixed(2);
    el.style.display = 'flex';
    fetch('/api/payment/create-checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') },
        body: JSON.stringify({ amount: amount })
    }).then(function(r) { return r.json(); }).then(function(data) {
        if (data.url) window.location.href = data.url;
        else if (data.clientSecret) { el.querySelector('.sc339-status').textContent = 'Processing...'; }
        else { el.querySelector('.sc339-status').textContent = data.error || 'Payment setup failed'; }
    }).catch(function() { el.querySelector('.sc339-status').textContent = 'Connection error'; });
}
function _closeStripeCheckout() { var el = document.getElementById('stripeCheckout339'); if (el) el.style.display = 'none'; }


