/* ── 347-354 — player retention tracker ────────────────────────── */
var _retentionData = { firstVisit: null, lastVisit: null, totalVisits: 0, streak: 0 };
function _initRetentionTracker() {
    var stored = localStorage.getItem('ms_retention');
    var today = new Date().toISOString().split('T')[0];
    if (stored) {
        try { _retentionData = JSON.parse(stored); } catch(e) {}
    }
    if (!_retentionData.firstVisit) _retentionData.firstVisit = today;
    if (_retentionData.lastVisit === today) return;
    var lastDate = _retentionData.lastVisit ? new Date(_retentionData.lastVisit) : null;
    var todayDate = new Date(today);
    if (lastDate && (todayDate - lastDate) <= 86400000 * 1.5) {
        _retentionData.streak++;
    } else {
        _retentionData.streak = 1;
    }
    _retentionData.totalVisits++;
    _retentionData.lastVisit = today;
    localStorage.setItem('ms_retention', JSON.stringify(_retentionData));
    _showRetentionBadge();
}
function _showRetentionBadge() {
    if (_retentionData.streak >= 3) {
        var badge = document.getElementById('streakBadge348');
        if (!badge) {
            badge = document.createElement('div');
            badge.id = 'streakBadge348';
            badge.className = 'streak-badge';
            document.body.appendChild(badge);
        }
        badge.innerHTML = '<span class="streak-fire">&#128293;</span> ' + _retentionData.streak + '-Day Streak!';
        badge.style.display = 'block';
        setTimeout(function() { badge.style.display = 'none'; }, 5000);
    }
}


/* ── 347-354 — cohort analysis widget ──────────────────────────── */
function _initCohortAnalysis() {
    var cohort = localStorage.getItem('ms_cohort');
    if (!cohort) {
        var now = new Date();
        cohort = now.getFullYear() + '-W' + Math.ceil((now.getDate() + new Date(now.getFullYear(),0,1).getDay()) / 7);
        localStorage.setItem('ms_cohort', cohort);
    }
    console.log('[Cohort] Player cohort:', cohort);
    _trackCohortEvent('session_start');
}
function _trackCohortEvent(eventName) {
    var cohort = localStorage.getItem('ms_cohort') || 'unknown';
    var events = JSON.parse(localStorage.getItem('ms_cohort_events') || '[]');
    events.push({ cohort: cohort, event: eventName, ts: Date.now() });
    if (events.length > 500) events = events.slice(-500);
    localStorage.setItem('ms_cohort_events', JSON.stringify(events));
}


/* ── 347-354 — churn prediction alert ─────────────────────────── */
function _checkChurnRisk() {
    var stored = localStorage.getItem('ms_retention');
    if (!stored) return;
    var data;
    try { data = JSON.parse(stored); } catch(e) { return; }
    var lastVisit = data.lastVisit ? new Date(data.lastVisit) : null;
    if (!lastVisit) return;
    var daysSince = Math.floor((Date.now() - lastVisit.getTime()) / 86400000);
    if (daysSince >= 3 && daysSince < 7) {
        _showChurnOffer('welcome-back', 'Welcome back! Here\'s 10 free spins on us!', 10);
    } else if (daysSince >= 7) {
        _showChurnOffer('win-back', 'We missed you! Claim your 25 free spins + 50% deposit bonus!', 25);
    }
}
function _showChurnOffer(type, message, spins) {
    var shown = localStorage.getItem('ms_churn_offer_' + type);
    var today = new Date().toISOString().split('T')[0];
    if (shown === today) return;
    localStorage.setItem('ms_churn_offer_' + type, today);
    var toast = document.createElement('div');
    toast.className = 'churn-offer-toast';
    toast.innerHTML = '<div class="churn-offer-content"><span class="churn-icon">&#127873;</span><p>' + message + '</p>' +
        '<button onclick="this.parentElement.parentElement.remove();" class="churn-claim-btn">Claim Now</button></div>';
    document.body.appendChild(toast);
    setTimeout(function() { if (toast.parentElement) toast.remove(); }, 15000);
}


