/* ── 347-354 — daily login bonus ──────────────────────────────── */
var _dailyBonusRewards = [100, 200, 300, 500, 750, 1000, 2000];
function _checkDailyLoginBonus() {
    var lastClaim = localStorage.getItem('ms_daily_bonus_date');
    var today = new Date().toISOString().split('T')[0];
    if (lastClaim === today) return;
    var streak = parseInt(localStorage.getItem('ms_daily_bonus_streak') || '0');
    var lastDate = lastClaim ? new Date(lastClaim) : null;
    var todayDate = new Date(today);
    if (lastDate && (todayDate - lastDate) > 86400000 * 1.5) {
        streak = 0;
    }
    var dayIndex = Math.min(streak, _dailyBonusRewards.length - 1);
    var reward = _dailyBonusRewards[dayIndex];
    _showDailyBonusModal(reward, dayIndex + 1, streak);
}
function _showDailyBonusModal(reward, day, streak) {
    var modal = document.createElement('div');
    modal.id = 'dailyBonusModal352';
    modal.className = 'daily-bonus-overlay';
    modal.innerHTML = '<div class="daily-bonus-card">' +
        '<h2>Daily Login Bonus!</h2>' +
        '<div class="daily-bonus-day">Day ' + day + '</div>' +
        '<div class="daily-bonus-reward">' + reward.toLocaleString() + ' Credits</div>' +
        '<div class="daily-bonus-week">' + _dailyBonusRewards.map(function(r, i) {
            return '<span class="db-day ' + (i < day ? 'db-claimed' : i === day - 1 ? 'db-today' : '') + '">' + (i + 1) + '</span>';
        }).join('') + '</div>' +
        '<button onclick="_claimDailyBonus(&quot; + reward + &quot;, &quot; + (streak + 1) + &quot;)" class="daily-claim-btn">Claim Reward</button></div>';
    document.body.appendChild(modal);
}
function _claimDailyBonus(reward, newStreak) {
    var today = new Date().toISOString().split('T')[0];
    localStorage.setItem('ms_daily_bonus_date', today);
    localStorage.setItem('ms_daily_bonus_streak', newStreak.toString());
    if (typeof credits !== 'undefined') credits += reward;
    var el = document.getElementById('dailyBonusModal352');
    if (el) el.remove();
    _trackCohortEvent('daily_bonus_claimed');
}


