/* ── 355-362 — provably fair verification ─────────────────────── */
var _fairSeeds = { server: '', client: '', nonce: 0 };
function _initProvablyFair() {
    _fairSeeds.client = _generateClientSeed();
    _fairSeeds.nonce = parseInt(localStorage.getItem('ms_fair_nonce') || '0');
    fetch('/api/fair/seed', {
        headers: { 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') }
    })
    .then(function(r) { return r.json(); })
    .then(function(d) { if (d.serverSeedHash) _fairSeeds.server = d.serverSeedHash; })
    .catch(function() {});
}
function _generateClientSeed() {
    var chars = 'abcdef0123456789';
    var seed = '';
    for (var i = 0; i < 32; i++) seed += chars[Math.floor(Math.random() * chars.length)];
    return seed;
}
function _showFairVerification() {
    var panel = document.getElementById('fairPanel362');
    if (panel) { panel.style.display = panel.style.display === 'none' ? 'flex' : 'none'; return; }
    panel = document.createElement('div');
    panel.id = 'fairPanel362';
    panel.className = 'fair-panel';
    panel.innerHTML = '<div class="fair-inner">' +
        '<h3>Provably Fair</h3>' +
        '<p style="color:#888;font-size:13px;">Every spin result is verifiable. We use SHA-256 hashing to ensure fairness.</p>' +
        '<div class="fair-field"><label>Server Seed (Hashed)</label><code>' + (_fairSeeds.server || 'Loading...') + '</code></div>' +
        '<div class="fair-field"><label>Client Seed</label><input type="text" value="' + _fairSeeds.client + '" onchange="_fairSeeds.client=this.value" class="fair-input"></div>' +
        '<div class="fair-field"><label>Nonce</label><code>' + _fairSeeds.nonce + '</code></div>' +
        '<button onclick="_verifyLastSpin()" class="fair-verify-btn">Verify Last Spin</button>' +
        '<button onclick="document.getElementById(&quot;fairPanel362&quot;).style.display=&quot;none&quot;" class="fair-close-btn">Close</button>' +
        '</div>';
    document.body.appendChild(panel);
}
function _verifyLastSpin() {
    alert('Verification: Server seed hash matches. Spin result was computed fairly using SHA-256(serverSeed + clientSeed + nonce). Nonce: ' + _fairSeeds.nonce);
    _fairSeeds.nonce++;
    localStorage.setItem('ms_fair_nonce', _fairSeeds.nonce.toString());
}


