/* ── 363-370 — session security monitor ──────────────────────── */
var _sessionSecurity = { startTime: Date.now(), lastActivity: Date.now(), ipHash: '' };
function _initSessionSecurity() {
    document.addEventListener('mousemove', _updateActivity);
    document.addEventListener('keydown', _updateActivity);
    document.addEventListener('click', _updateActivity);
    setInterval(_checkSessionTimeout, 60000);
    _detectSuspiciousActivity();
}
function _updateActivity() { _sessionSecurity.lastActivity = Date.now(); }
function _checkSessionTimeout() {
    var idle = Date.now() - _sessionSecurity.lastActivity;
    if (idle > 30 * 60000) {
        alert('Session expired due to inactivity. Please log in again.');
        window.location.reload();
    } else if (idle > 25 * 60000) {
        var banner = document.getElementById('sessionWarnBanner');
        if (!banner) {
            banner = document.createElement('div');
            banner.id = 'sessionWarnBanner';
            banner.className = 'session-warn-banner';
            banner.innerHTML = '<span>\u23F0 Your session will expire in 5 minutes due to inactivity</span>';
            document.body.appendChild(banner);
        }
    }
}
function _detectSuspiciousActivity() {
    var devtools = false;
    var threshold = 160;
    setInterval(function() {
        if (window.outerWidth - window.innerWidth > threshold || window.outerHeight - window.innerHeight > threshold) {
            if (!devtools) {
                devtools = true;
                console.warn('[Security] DevTools detected');
            }
        } else { devtools = false; }
    }, 5000);
}


