var _rateLimitState = { requests: 0, windowStart: Date.now(), maxPerMinute: 60, blocked: false };
function _checkRateLimit(action) {
    var now = Date.now();
    if (now - _rateLimitState.windowStart > 60000) {
        _rateLimitState.requests = 0;
        _rateLimitState.windowStart = now;
        _rateLimitState.blocked = false;
    }
    _rateLimitState.requests++;
    if (_rateLimitState.requests > _rateLimitState.maxPerMinute) {
        if (!_rateLimitState.blocked) {
            _rateLimitState.blocked = true;
            _showRateLimitWarning();
        }
        return false;
    }
    return true;
}
