/* ── 363-370 — fraud detection score ──────────────────────────── */
var _fraudScore = 0;
function _calculateFraudScore() {
    var score = 0;
    var stored = localStorage.getItem('ms_retention');
    if (stored) {
        var data = JSON.parse(stored);
        if (data.totalVisits < 2) score += 15;
    } else { score += 20; }
    if (!localStorage.getItem('ms_kyc_status') || localStorage.getItem('ms_kyc_status') === 'unverified') score += 25;
    if (_amlDailyTotal > 5000) score += 20;
    if (_amlDepositCount > 3) score += 10;
    if (!_2faEnabled) score += 10;
    _fraudScore = Math.min(100, score);
    if (_fraudScore >= 70) {
        console.warn('[Fraud] High risk score:', _fraudScore);
        fetch('/api/admin/fraud/alert', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') },
            body: JSON.stringify({ score: _fraudScore, timestamp: Date.now() })
        }).catch(function() {});
    }
    return _fraudScore;
}


