/* â”€â”€ 371-378 — haptic feedback system â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
var _hapticEnabled = true;
function _initHaptic() {
    _hapticEnabled = localStorage.getItem('ms_haptic') !== 'false';
}
function _hapticBuzz(type) {
    if (!_hapticEnabled || !navigator.vibrate) return;
    switch(type) {
        case 'spin': navigator.vibrate(50); break;
        case 'win': navigator.vibrate([100, 50, 100, 50, 200]); break;
        case 'bigwin': navigator.vibrate([200, 100, 200, 100, 200, 100, 400]); break;
        case 'click': navigator.vibrate(20); break;
        case 'error': navigator.vibrate([300, 100, 300]); break;
        default: navigator.vibrate(30);
    }
}
function _toggleHaptic() {
    _hapticEnabled = !_hapticEnabled;
    localStorage.setItem('ms_haptic', _hapticEnabled.toString());
    _hapticBuzz('click');
}


/* â”€â”€ 371-378 — swipe gesture navigation â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
var _touchStart = { x: 0, y: 0 };
function _initSwipeGestures() {
    document.addEventListener('touchstart', function(e) {
        _touchStart.x = e.changedTouches[0].screenX;
        _touchStart.y = e.changedTouches[0].screenY;
    }, { passive: true });
    document.addEventListener('touchend', function(e) {
        var dx = e.changedTouches[0].screenX - _touchStart.x;
        var dy = e.changedTouches[0].screenY - _touchStart.y;
        var absDx = Math.abs(dx);
        var absDy = Math.abs(dy);
        if (absDx < 80 && absDy < 80) return;
        if (absDx > absDy) {
            if (dx > 0) _onSwipe('right');
            else _onSwipe('left');
        } else {
            if (dy > 0) _onSwipe('down');
            else _onSwipe('up');
        }
    }, { passive: true });
}
function _onSwipe(dir) {
    _hapticBuzz('click');
    switch(dir) {
        case 'left': _showGameSelector(); break;
        case 'right': _showLeaderboard(); break;
        case 'up': break;
        case 'down': break;
    }
}


/* â”€â”€ 371-378 — offline mode indicator â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
var _isOnline = navigator.onLine;
function _initOfflineDetection() {
    window.addEventListener('online', function() {
        _isOnline = true;
        _updateOnlineStatus();
    });
    window.addEventListener('offline', function() {
        _isOnline = false;
        _updateOnlineStatus();
    });
    _updateOnlineStatus();
}
function _updateOnlineStatus() {
    var indicator = document.getElementById('offlineIndicator374');
    if (!_isOnline) {
        if (!indicator) {
            indicator = document.createElement('div');
            indicator.id = 'offlineIndicator374';
            indicator.className = 'offline-indicator';
            indicator.innerHTML = '<span>\u{1F4E1}</span> You are offline. Some features may be limited.';
            document.body.appendChild(indicator);
        }
        indicator.style.display = 'flex';
    } else if (indicator) {
        indicator.style.display = 'none';
    }
}


/* â”€â”€ 371-378 â€” screen orientation handler â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
function _initOrientationHandler() {
    if (!screen.orientation) return;
    window.addEventListener('orientationchange', function() {
        _handleOrientation();
    });
    _handleOrientation();
}
function _handleOrientation() {
    var isLandscape = window.innerWidth > window.innerHeight;
    var hint = document.getElementById('orientationHint375');
    if (isLandscape && window.innerWidth < 900) {
        if (!hint) {
            hint = document.createElement('div');
            hint.id = 'orientationHint375';
            hint.className = 'orientation-hint';
            hint.innerHTML = '<span>\u{1F504}</span> Rotate your device for the best experience';
            document.body.appendChild(hint);
        }
        hint.style.display = 'flex';
        setTimeout(function() { if (hint.parentElement) hint.style.display = 'none'; }, 5000);
    } else if (hint) {
        hint.style.display = 'none';
    }
}


/* â”€â”€ 371-378 â€” battery saver mode â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
var _batterySaver = false;
function _initBatterySaver() {
    if (!navigator.getBattery) return;
    navigator.getBattery().then(function(battery) {
        _checkBattery(battery);
        battery.addEventListener('levelchange', function() { _checkBattery(battery); });
    });
}
function _checkBattery(battery) {
    if (battery.level < 0.15 && !battery.charging && !_batterySaver) {
        _enableBatterySaver();
    } else if ((battery.level >= 0.3 || battery.charging) && _batterySaver) {
        _disableBatterySaver();
    }
}
function _enableBatterySaver() {
    _batterySaver = true;
    document.body.classList.add('battery-saver');
    var notice = document.createElement('div');
    notice.id = 'batterySaverNotice376';
    notice.className = 'battery-saver-notice';
    notice.innerHTML = '<span>\u{1F50B}</span> Battery Saver mode enabled. Animations reduced.';
    document.body.appendChild(notice);
    setTimeout(function() { if (notice.parentElement) notice.remove(); }, 5000);
}
function _disableBatterySaver() {
    _batterySaver = false;
    document.body.classList.remove('battery-saver');
}


