/* ── 387-394 — sound effects manager ──────────────────────────── */
var _sfxEnabled = true;
var _sfxVolume = 0.5;
function _initSFX() {
    _sfxEnabled = localStorage.getItem('ms_sfx') !== 'false';
    _sfxVolume = parseFloat(localStorage.getItem('ms_sfx_vol') || '0.5');
}
function _playSFX(type) {
    if (!_sfxEnabled) return;
    try {
        var ctx = new (window.AudioContext || window.webkitAudioContext)();
        var osc = ctx.createOscillator();
        var gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);
        gain.gain.value = _sfxVolume * 0.3;
        switch(type) {
            case 'spin': osc.frequency.value = 440; osc.type = 'sine'; gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3); osc.start(); osc.stop(ctx.currentTime + 0.3); break;
            case 'win': osc.frequency.value = 880; osc.type = 'triangle'; gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5); osc.start(); osc.stop(ctx.currentTime + 0.5); break;
            case 'bigwin': osc.frequency.value = 660; osc.type = 'sawtooth'; gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.0); osc.start(); osc.stop(ctx.currentTime + 1.0); break;
            case 'click': osc.frequency.value = 1200; osc.type = 'square'; gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.05); osc.start(); osc.stop(ctx.currentTime + 0.05); break;
        }
    } catch(e) {}
}


