/* ── 395-402 — scratch card mini-game ─────────────────────────── */
function _showScratchCard() {
    var prize = _generateScratchPrize();
    var modal = document.createElement('div');
    modal.id = 'scratchCard398';
    modal.className = 'scratch-overlay';
    var cells = [];
    for (var i = 0; i < 9; i++) {
        var isWin = i < prize.matches;
        cells.push('<div class="scratch-cell" onclick="_revealScratch(this, &quot; + (isWin ? prize.amount : 0) + &quot;)" data-revealed="false"><div class="scratch-cover">?</div><div class="scratch-prize">' + (isWin ? '$' + prize.amount : '\u274C') + '</div></div>');
    }
    cells.sort(function() { return Math.random() - 0.5; });
    modal.innerHTML = '<div class="scratch-card-inner"><h3>\u{1F3AB} Daily Scratch Card</h3><p style="color:#888;font-size:12px;">Match 3 to win! Tap to reveal.</p>' +
        '<div class="scratch-grid">' + cells.join('') + '</div>' +
        '<button onclick="document.getElementById(\&quot;scratchCard398\&quot;).remove()" class="scratch-close-btn">Close</button></div>';
    document.body.appendChild(modal);
}
function _generateScratchPrize() {
    var rand = Math.random();
    if (rand < 0.01) return { amount: 100, matches: 3 };
    if (rand < 0.05) return { amount: 25, matches: 3 };
    if (rand < 0.15) return { amount: 5, matches: 3 };
    return { amount: 0, matches: Math.floor(Math.random() * 3) };
}
var _scratchRevealed = 0;
function _revealScratch(el, amount) {
    if (el.dataset.revealed === 'true') return;
    el.dataset.revealed = 'true';
    el.querySelector('.scratch-cover').style.display = 'none';
    el.querySelector('.scratch-prize').style.display = 'flex';
    _scratchRevealed++;
    _hapticBuzz('click');
    if (_scratchRevealed >= 9) {
        _scratchRevealed = 0;
        if (amount > 0) {
            setTimeout(function() { alert('You won $' + amount + '!'); if (typeof credits !== 'undefined') credits += amount; }, 500);
        }
    }
}


/* ── 395-402 — wheel of fortune bonus ─────────────────────────── */
var _wheelPrizes = [5, 10, 25, 50, 100, 250, 500, 1000];
function _showWheelOfFortune() {
    var modal = document.createElement('div');
    modal.id = 'wheelModal399';
    modal.className = 'wheel-overlay';
    var segments = _wheelPrizes.map(function(p, i) {
        var angle = (360 / _wheelPrizes.length) * i;
        var color = i % 2 === 0 ? '#ffd700' : '#9b59b6';
        return '<div class="wheel-segment" style="transform:rotate(' + angle + 'deg);background:' + color + '"><span>$' + p + '</span></div>';
    }).join('');
    modal.innerHTML = '<div class="wheel-inner"><h2>\u{1F3A1} Wheel of Fortune</h2>' +
        '<div class="wheel-container"><div id="wheelSpinner399" class="wheel-spinner">' + segments + '</div><div class="wheel-pointer">\u25BC</div></div>' +
        '<button onclick="_spinWheel()" id="wheelSpinBtn399" class="wheel-spin-btn">SPIN!</button>' +
        '<button onclick="document.getElementById(\&quot;wheelModal399\&quot;).remove()" class="wheel-close-btn">Close</button></div>';
    document.body.appendChild(modal);
}
function _spinWheel() {
    var btn = document.getElementById('wheelSpinBtn399');
    btn.disabled = true;
    btn.textContent = 'Spinning...';
    var spinner = document.getElementById('wheelSpinner399');
    var winIndex = Math.floor(Math.random() * _wheelPrizes.length);
    var targetAngle = 1440 + (360 / _wheelPrizes.length) * winIndex;
    spinner.style.transition = 'transform 4s cubic-bezier(0.2, 0.8, 0.3, 1)';
    spinner.style.transform = 'rotate(' + targetAngle + 'deg)';
    setTimeout(function() {
        var prize = _wheelPrizes[winIndex];
        alert('You won $' + prize + '!');
        if (typeof credits !== 'undefined') credits += prize;
        btn.disabled = false;
        btn.textContent = 'SPIN!';
    }, 4500);
}


