// --- Sprint 425 — Challenge Mode ---
var _challengeData = { active: false, type: null, target: 0, progress: 0, reward: 0, endTime: 0 };
function _initChallengeMode() {
    _challengeData.active = false;
    setTimeout(function() { _offerChallenge(); }, 10000);
}
function _offerChallenge() {
    if (_challengeData.active) return;
    var challenges = [
        { type: 'spins', target: 20, reward: 200, desc: 'Complete 20 spins in 5 minutes' },
        { type: 'wins', target: 5, reward: 300, desc: 'Get 5 wins in 10 minutes' },
        { type: 'bigwin', target: 1, reward: 500, desc: 'Hit a 10x+ win in 15 minutes' }
    ];
    var c = challenges[Math.floor(Math.random() * challenges.length)];
    var el = document.getElementById('challengeOfferOverlay');
    if (!el) {
        el = document.createElement('div');
        el.id = 'challengeOfferOverlay';
        el.className = 'challenge-offer-overlay';
        document.body.appendChild(el);
    }
    el.innerHTML = '<div class="challenge-card">' +
        '<h3>CHALLENGE!</h3>' +
        '<p>' + c.desc + '</p>' +
        '<p class="challenge-reward">Reward: ' + c.reward + ' coins</p>' +
        '<button onclick="_acceptChallenge(&quot;&quot; + c.type + &quot;&quot;,&quot; + c.target + &quot;,&quot; + c.reward + &quot;)" class="challenge-accept">Accept</button>' +
        '<button onclick="document.getElementById(&quot;challengeOfferOverlay&quot;).style.display=&quot;none&quot;" class="challenge-decline">Decline</button>' +
        '</div>';
    el.style.display = 'flex';
}
function _acceptChallenge(type, target, reward) {
    _challengeData = { active: true, type: type, target: target, progress: 0, reward: reward, endTime: Date.now() + 600000 };
    document.getElementById('challengeOfferOverlay').style.display = 'none';
    _showChallengeProgress();
}
function _updateChallengeProgress(type, value) {
    if (!_challengeData.active) return;
    if (Date.now() > _challengeData.endTime) { _challengeData.active = false; return; }
    if (_challengeData.type === type) {
        _challengeData.progress += (value || 1);
        _showChallengeProgress();
        if (_challengeData.progress >= _challengeData.target) {
            if (typeof balance !== 'undefined') balance += _challengeData.reward;
            if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
            _challengeData.active = false;
            _showChallengeComplete(_challengeData.reward);
        }
    }
}
function _showChallengeProgress() {
    var el = document.getElementById('challengeProgressBar');
    if (!el) {
        el = document.createElement('div');
        el.id = 'challengeProgressBar';
        el.className = 'challenge-progress-bar';
        document.body.appendChild(el);
    }
    var pct = Math.min(100, (_challengeData.progress / _challengeData.target) * 100);
    el.innerHTML = 'Challenge: ' + _challengeData.progress + '/' + _challengeData.target + ' <div class="challenge-fill" style="width:' + pct + '%"></div>';
    el.style.display = 'block';
}
function _showChallengeComplete(reward) {
    var el = document.getElementById('challengeProgressBar');
    if (el) { el.innerHTML = 'CHALLENGE COMPLETE! +' + reward + ' coins'; setTimeout(function() { el.style.display = 'none'; }, 3000); }
}


