var _loyaltyPtsV2 = 0;
function _initLoyaltyExchange() {
    try { _loyaltyPtsV2 = parseInt(localStorage.getItem('ms_loyaltyPtsV2') || '0'); } catch(e) { _loyaltyPtsV2 = 0; }
}
function _earnLoyaltyPoints(betAmount) {
    var pts = Math.floor((betAmount || 0) * 10);
    _loyaltyPtsV2 += pts;
    try { localStorage.setItem('ms_loyaltyPtsV2', _loyaltyPtsV2.toString()); } catch(e) {}
}
function _openLoyaltyExchange() {
    var el = document.getElementById('loyaltyExchangeOverlay');
    if (!el) {
        el = document.createElement('div');
        el.id = 'loyaltyExchangeOverlay';
        el.className = 'loyalty-exchange-overlay';
        document.body.appendChild(el);
    }
    var rewards = [
        { name: '100 Coins', cost: 500, coins: 100 },
        { name: '500 Coins', cost: 2000, coins: 500 },
        { name: '2x Multiplier (1 spin)', cost: 1000, coins: 0, perk: 'mult2x' },
        { name: 'Free Spin Bundle', cost: 3000, coins: 0, perk: 'freespins' }
    ];
    var html = '<div class="loyalty-ex-card"><h3>Loyalty Exchange</h3><p>Points: <strong>' + _loyaltyPtsV2 + '</strong></p><div class="loyalty-items">';
    rewards.forEach(function(r, i) {
        html += '<div class="loyalty-item"><span>' + r.name + '</span><span>' + r.cost + ' pts</span>' +
            '<button onclick="_redeemLoyalty(&quot; + i + &quot;,&quot; + r.cost + &quot;,&quot; + r.coins + &quot;)" ' + (_loyaltyPtsV2 < r.cost ? 'disabled' : '') + '>Redeem</button></div>';
    });
    html += '</div><button onclick="document.getElementById(&quot;loyaltyExchangeOverlay&quot;).style.display=&quot;none&quot;" class="loyalty-close">Close</button></div>';
    el.innerHTML = html;
    el.style.display = 'flex';
}
function _redeemLoyalty(idx, cost, coins) {
    if (_loyaltyPtsV2 < cost) return;
    _loyaltyPtsV2 -= cost;
    try { localStorage.setItem('ms_loyaltyPtsV2', _loyaltyPtsV2.toString()); } catch(e) {}
    if (coins > 0) {
        if (typeof balance !== 'undefined') balance += coins;
        if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
    }
    _openLoyaltyExchange();
}


