// --- Sprint 443 — Session Time Limits ---
var _sessionStartTime = Date.now();
var _sessionTimeLimitMs = 3600000; // 1 hour default
var _sessionTimeWarnings = [0.75, 0.9, 1.0]; // warn at 75%, 90%, 100%
var _sessionWarningShown = {};
function _initSessionTimeLimits() {
    _sessionStartTime = Date.now();
    _sessionWarningShown = {};
    try {
        var limit = localStorage.getItem('ms_sessionTimeLimit');
        if (limit) _sessionTimeLimitMs = parseInt(limit);
    } catch(e) {}
    setInterval(_checkSessionTime, 30000);
}
function _checkSessionTime() {
    var elapsed = Date.now() - _sessionStartTime;
    var pct = elapsed / _sessionTimeLimitMs;
    for (var i = 0; i < _sessionTimeWarnings.length; i++) {
        var threshold = _sessionTimeWarnings[i];
        if (pct >= threshold && !_sessionWarningShown[threshold]) {
            _sessionWarningShown[threshold] = true;
            if (threshold >= 1.0) _showSessionExpired();
            else _showSessionTimeWarning(Math.round(threshold * 100));
        }
    }
}
function _showSessionTimeWarning(pct) {
    var remaining = Math.max(0, Math.round((_sessionTimeLimitMs - (Date.now() - _sessionStartTime)) / 60000));
    var el = document.getElementById('sessionTimeWarning');
    if (!el) { el = document.createElement('div'); el.id = 'sessionTimeWarning'; el.className = 'session-time-warning'; document.body.appendChild(el); }
    el.innerHTML = '<div class="stw-content"><strong>Session Time Alert</strong><p>You have been playing for a while. ' + remaining + ' minutes remaining.</p><button onclick="this.parentElement.parentElement.style.display=&quot;none&quot;">Continue</button><button onclick="_endSession()">Take a Break</button></div>';
    el.style.display = 'flex';
}
function _showSessionExpired() {
    var el = document.getElementById('sessionExpiredOverlay');
    if (!el) { el = document.createElement('div'); el.id = 'sessionExpiredOverlay'; el.className = 'session-expired-overlay'; document.body.appendChild(el); }
    el.innerHTML = '<div class="se-card"><h3>Session Limit Reached</h3><p>You have reached your session time limit. Please take a break.</p><p>Gambling should be fun, not a way to make money.</p><button onclick="_endSession()">Log Out</button><button onclick="_extendSession()">Extend 30 min</button></div>';
    el.style.display = 'flex';
}
function _endSession() { window.location.href = '/'; }
function _extendSession() {
    _sessionTimeLimitMs += 1800000;
    _sessionWarningShown = {};
    var el = document.getElementById('sessionExpiredOverlay');
    if (el) el.style.display = 'none';
}


// --- Sprint 444 — Reality Check Popups ---
var _realityCheckIntervalMs = 1800000; // every 30 min
var _realityCheckTimer = null;
var _realityCheckSessionStats = { spins: 0, wagered: 0, won: 0, netResult: 0 };
function _initRealityCheck() {
    _realityCheckSessionStats = { spins: 0, wagered: 0, won: 0, netResult: 0 };
    clearInterval(_realityCheckTimer);
    try { var i = localStorage.getItem('ms_realityCheckInterval'); if (i) _realityCheckIntervalMs = parseInt(i); } catch(e) {}
    _realityCheckTimer = setInterval(_showRealityCheck, _realityCheckIntervalMs);
}
function _trackRealityStats(bet, win) {
    _realityCheckSessionStats.spins++;
    _realityCheckSessionStats.wagered += (bet || 0);
    _realityCheckSessionStats.won += (win || 0);
    _realityCheckSessionStats.netResult = _realityCheckSessionStats.won - _realityCheckSessionStats.wagered;
}
function _showRealityCheck() {
    var elapsed = Math.round((Date.now() - _sessionStartTime) / 60000);
    var s = _realityCheckSessionStats;
    var el = document.getElementById('realityCheckOverlay');
    if (!el) { el = document.createElement('div'); el.id = 'realityCheckOverlay'; el.className = 'reality-check-overlay'; document.body.appendChild(el); }
    el.innerHTML = '<div class="rc-card"><h3>Reality Check</h3>' +
        '<div class="rc-stat"><span>Time Playing:</span><span>' + elapsed + ' minutes</span></div>' +
        '<div class="rc-stat"><span>Spins:</span><span>' + s.spins + '</span></div>' +
        '<div class="rc-stat"><span>Wagered:</span><span>' + s.wagered.toFixed(2) + '</span></div>' +
        '<div class="rc-stat"><span>Won:</span><span>' + s.won.toFixed(2) + '</span></div>' +
        '<div class="rc-stat rc-net ' + (s.netResult >= 0 ? 'rc-positive' : 'rc-negative') + '"><span>Net Result:</span><span>' + (s.netResult >= 0 ? '+' : '') + s.netResult.toFixed(2) + '</span></div>' +
        '<p class="rc-msg">Remember: gambling should be entertaining, not a source of income.</p>' +
        '<button onclick="document.getElementById(&quot;realityCheckOverlay&quot;).style.display=&quot;none&quot;" class="rc-continue">Continue Playing</button>' +
        '<button onclick="_endSession()" class="rc-stop">Stop Playing</button>' +
        '<a href="#" onclick="_openRGInfo()" class="rc-help">Need Help?</a></div>';
    el.style.display = 'flex';
}


// --- Sprint 445 — Self-Exclusion Portal ---
function _initSelfExclusion() {
    try {
        var excl = localStorage.getItem('ms_selfExcluded');
        if (excl) {
            var data = JSON.parse(excl);
            if (data.until && Date.now() < data.until) {
                _enforceSelfExclusion(data);
                return;
            } else {
                localStorage.removeItem('ms_selfExcluded');
            }
        }
    } catch(e) {}
}
function _openSelfExclusionPortal() {
    var el = document.getElementById('selfExclusionOverlay');
    if (!el) { el = document.createElement('div'); el.id = 'selfExclusionOverlay'; el.className = 'self-exclusion-overlay'; document.body.appendChild(el); }
    el.innerHTML = '<div class="se-portal-card"><h3>Self-Exclusion</h3><p>If you feel gambling is becoming a problem, you can exclude yourself from playing.</p>' +
        '<div class="se-options">' +
        '<button onclick="_selfExclude(1)">24 Hours</button>' +
        '<button onclick="_selfExclude(7)">7 Days</button>' +
        '<button onclick="_selfExclude(30)">30 Days</button>' +
        '<button onclick="_selfExclude(180)">6 Months</button>' +
        '</div>' +
        '<p class="se-warning">This action cannot be reversed early.</p>' +
        '<button onclick="document.getElementById(&quot;selfExclusionOverlay&quot;).style.display=&quot;none&quot;" class="se-cancel">Cancel</button>' +
        '<div class="se-helplines"><strong>Support:</strong><br>National Problem Gambling Helpline: 1-800-522-4700<br>GamCare: 0808 8020 133<br>Gamblers Anonymous: gamblersanonymous.org</div></div>';
    el.style.display = 'flex';
}
function _selfExclude(days) {
    var data = { until: Date.now() + (days * 86400000), days: days };
    localStorage.setItem('ms_selfExcluded', JSON.stringify(data));
    _enforceSelfExclusion(data);
}
function _enforceSelfExclusion(data) {
    var el = document.getElementById('selfExclusionBlock');
    if (!el) { el = document.createElement('div'); el.id = 'selfExclusionBlock'; el.className = 'self-exclusion-block'; document.body.appendChild(el); }
    var remaining = Math.ceil((data.until - Date.now()) / 86400000);
    el.innerHTML = '<div class="se-block-card"><h3>Account Self-Excluded</h3><p>You have excluded yourself for ' + data.days + ' days.</p><p>' + remaining + ' days remaining.</p><p>If you need support, please contact:</p><p>1-800-522-4700 (National Problem Gambling Helpline)</p></div>';
    el.style.display = 'flex';
}


// --- Sprint 446 — Deposit Limits Dashboard ---
var _depositLimitsV2 = { daily: 500, weekly: 2000, monthly: 5000, dailyUsed: 0, weeklyUsed: 0, monthlyUsed: 0 };
function _initDepositLimitsV2() {
    try { var saved = localStorage.getItem('ms_depositLimitsV2'); if (saved) _depositLimitsV2 = JSON.parse(saved); } catch(e) {}
}
function _checkDepositLimit(amount) {
    if (_depositLimitsV2.dailyUsed + amount > _depositLimitsV2.daily) return { allowed: false, reason: 'Daily deposit limit reached ($' + _depositLimitsV2.daily + ')' };
    if (_depositLimitsV2.weeklyUsed + amount > _depositLimitsV2.weekly) return { allowed: false, reason: 'Weekly deposit limit reached ($' + _depositLimitsV2.weekly + ')' };
    if (_depositLimitsV2.monthlyUsed + amount > _depositLimitsV2.monthly) return { allowed: false, reason: 'Monthly deposit limit reached ($' + _depositLimitsV2.monthly + ')' };
    return { allowed: true };
}
function _openDepositLimitsDashboard() {
    var el = document.getElementById('depositLimitsDash');
    if (!el) { el = document.createElement('div'); el.id = 'depositLimitsDash'; el.className = 'deposit-limits-dash'; document.body.appendChild(el); }
    var d = _depositLimitsV2;
    el.innerHTML = '<div class="dl-card"><h3>Deposit Limits</h3>' +
        '<div class="dl-row"><label>Daily Limit:</label><span>$' + d.dailyUsed.toFixed(0) + ' / $' + d.daily + '</span><div class="dl-bar"><div class="dl-fill" style="width:' + Math.min(100,(d.dailyUsed/d.daily)*100) + '%"></div></div></div>' +
        '<div class="dl-row"><label>Weekly Limit:</label><span>$' + d.weeklyUsed.toFixed(0) + ' / $' + d.weekly + '</span><div class="dl-bar"><div class="dl-fill" style="width:' + Math.min(100,(d.weeklyUsed/d.weekly)*100) + '%"></div></div></div>' +
        '<div class="dl-row"><label>Monthly Limit:</label><span>$' + d.monthlyUsed.toFixed(0) + ' / $' + d.monthly + '</span><div class="dl-bar"><div class="dl-fill" style="width:' + Math.min(100,(d.monthlyUsed/d.monthly)*100) + '%"></div></div></div>' +
        '<div class="dl-edit"><h4>Update Limits</h4><label>Daily: <input type="number" id="dlDaily" value="' + d.daily + '" min="10"></label>' +
        '<label>Weekly: <input type="number" id="dlWeekly" value="' + d.weekly + '" min="50"></label>' +
        '<label>Monthly: <input type="number" id="dlMonthly" value="' + d.monthly + '" min="100"></label>' +
        '<button onclick="_updateDepositLimits()">Save Limits</button><p class="dl-note">Limit decreases take effect immediately. Increases take 24 hours.</p></div>' +
        '<button onclick="document.getElementById(&quot;depositLimitsDash&quot;).style.display=&quot;none&quot;" class="dl-close">Close</button></div>';
    el.style.display = 'flex';
}
function _updateDepositLimits() {
    var d = document.getElementById('dlDaily'), w = document.getElementById('dlWeekly'), m = document.getElementById('dlMonthly');
    if (d) _depositLimitsV2.daily = Math.max(10, parseInt(d.value) || 500);
    if (w) _depositLimitsV2.weekly = Math.max(50, parseInt(w.value) || 2000);
    if (m) _depositLimitsV2.monthly = Math.max(100, parseInt(m.value) || 5000);
    try { localStorage.setItem('ms_depositLimitsV2', JSON.stringify(_depositLimitsV2)); } catch(e) {}
    _openDepositLimitsDashboard();
}


// --- Sprint 447 — Cool-Off Period ---
function _initCoolOff() {}
function _startCoolOff(minutes) {
    var until = Date.now() + (minutes * 60000);
    try { localStorage.setItem('ms_coolOff', until.toString()); } catch(e) {}
    _showCoolOffScreen(until);
}
function _checkCoolOff() {
    try {
        var until = parseInt(localStorage.getItem('ms_coolOff') || '0');
        if (until && Date.now() < until) { _showCoolOffScreen(until); return true; }
        else localStorage.removeItem('ms_coolOff');
    } catch(e) {}
    return false;
}
function _showCoolOffScreen(until) {
    var el = document.getElementById('coolOffOverlay');
    if (!el) { el = document.createElement('div'); el.id = 'coolOffOverlay'; el.className = 'cool-off-overlay'; document.body.appendChild(el); }
    var update = function() {
        var remaining = Math.max(0, until - Date.now());
        if (remaining <= 0) { el.style.display = 'none'; localStorage.removeItem('ms_coolOff'); return; }
        var mins = Math.floor(remaining / 60000);
        var secs = Math.floor((remaining % 60000) / 1000);
        el.innerHTML = '<div class="co-card"><h3>Cool-Off Active</h3><div class="co-timer">' + mins + ':' + (secs < 10 ? '0' : '') + secs + '</div><p>Taking a break is a sign of responsible gambling.</p><p>Your account will be available when the timer expires.</p></div>';
        el.style.display = 'flex';
        setTimeout(update, 1000);
    };
    update();
}


