// --- Sprint 458 — Dynamic House Edge ---
var _houseEdgeConfig = { base: 0.04, minRTP: 0.92, maxRTP: 0.97, currentRTP: 0.95 };
function _initDynamicHouseEdge() {
    try { var saved = localStorage.getItem('ms_houseEdgeConfig'); if (saved) _houseEdgeConfig = JSON.parse(saved); } catch(e) {}
}
function _adjustHouseEdge(playerSegment, sessionLength) {
    var rtp = _houseEdgeConfig.currentRTP;
    if (playerSegment === 'whale') rtp = Math.min(_houseEdgeConfig.maxRTP, rtp + 0.01);
    if (playerSegment === 'new') rtp = Math.min(_houseEdgeConfig.maxRTP, rtp + 0.005);
    if (sessionLength > 60) rtp = Math.max(_houseEdgeConfig.minRTP, rtp - 0.005);
    _houseEdgeConfig.currentRTP = Math.max(_houseEdgeConfig.minRTP, Math.min(_houseEdgeConfig.maxRTP, rtp));
    try { localStorage.setItem('ms_houseEdgeConfig', JSON.stringify(_houseEdgeConfig)); } catch(e) {}
    return 1 - _houseEdgeConfig.currentRTP;
}
function _getHouseEdge() { return 1 - _houseEdgeConfig.currentRTP; }


// --- Sprint 459 — Lazy Loading ---
function _initLazyLoading() {
    if (!('IntersectionObserver' in window)) return;
    var observer = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
            if (entry.isIntersecting) {
                var img = entry.target;
                if (img.dataset.src) { img.src = img.dataset.src; delete img.dataset.src; }
                if (img.dataset.bg) { img.style.backgroundImage = 'url(' + img.dataset.bg + ')'; delete img.dataset.bg; }
                observer.unobserve(img);
            }
        });
    }, { rootMargin: '200px' });
    document.querySelectorAll('[data-src],[data-bg]').forEach(function(el) { observer.observe(el); });
}


// --- Sprint 460 — Image Optimization ---
function _initImageOptimization() {
    var supportsWebP = false;
    var testImg = new Image();
    testImg.onload = function() { supportsWebP = testImg.width > 0; if (supportsWebP) _convertImagesToWebP(); };
    testImg.onerror = function() { supportsWebP = false; };
    testImg.src = 'data:image/webp;base64,UklGRiIAAABXRUJQVlA4IBYAAAAwAQCdASoBAAEADsD+JaQAA3AAAAAA';
}
function _convertImagesToWebP() {
    document.querySelectorAll('img[src$=".png"],img[src$=".jpg"],img[src$=".jpeg"]').forEach(function(img) {
        var webpSrc = img.src.replace(/\.(png|jpe?g)$/i, '.webp');
        var testImg = new Image();
        testImg.onload = function() { img.src = webpSrc; };
        testImg.onerror = function() {};
        testImg.src = webpSrc;
    });
}


// --- Sprint 461 — Error Boundary ---
var _errorLog = [];
function _initErrorBoundary() {
    window.onerror = function(msg, url, line, col, err) {
        _logError({ type: 'uncaught', message: msg, url: url, line: line, col: col, stack: err ? err.stack : '' });
        return false;
    };
    window.addEventListener('unhandledrejection', function(e) {
        _logError({ type: 'promise', message: e.reason ? (e.reason.message || String(e.reason)) : 'Unknown promise rejection' });
    });
}
function _logError(err) {
    err.time = new Date().toISOString();
    _errorLog.push(err);
    if (_errorLog.length > 100) _errorLog.shift();
    _showErrorToast(err.message);
}
function _showErrorToast(msg) {
    var el = document.getElementById('errorToast');
    if (!el) { el = document.createElement('div'); el.id = 'errorToast'; el.className = 'error-toast'; document.body.appendChild(el); }
    el.textContent = 'Something went wrong. We are looking into it.';
    el.style.display = 'block';
    setTimeout(function() { el.style.display = 'none'; }, 4000);
}


