function _initClusterPays() {}
function _checkClusterPay(grid) {
    if (!grid || !Array.isArray(grid)) return 0;
    var clusters = {};
    for (var r = 0; r < grid.length; r++) {
        for (var c = 0; c < (grid[r] ? grid[r].length : 0); c++) {
            var sym = grid[r][c];
            if (!clusters[sym]) clusters[sym] = 0;
            clusters[sym]++;
        }
    }
    var clusterWin = 0;
    Object.keys(clusters).forEach(function(sym) {
        if (clusters[sym] >= 5 && sym !== 'empty') {
            clusterWin += clusters[sym] * 2;
            _showClusterEffect(sym, clusters[sym]);
        }
    });
    return clusterWin;
}
