// --- Sprint 481 — Secure Session Tokens ---
var _sessionToken = '';
function _initSecureSession() {
    _sessionToken = _generateSessionToken();
    try { sessionStorage.setItem('ms_sessionToken', _sessionToken); } catch(e) {}
    _validateSessionIntegrity();
}
function _generateSessionToken() {
    var arr = new Uint8Array(32);
    if (window.crypto && window.crypto.getRandomValues) window.crypto.getRandomValues(arr);
    else for (var i = 0; i < 32; i++) arr[i] = Math.floor(Math.random() * 256);
    return Array.from(arr).map(function(b) { return b.toString(16).padStart(2, '0'); }).join('');
}
function _validateSessionIntegrity() {
    setInterval(function() {
        try {
            var stored = sessionStorage.getItem('ms_sessionToken');
            if (stored && stored !== _sessionToken) {
                _flagSuspiciousActivity('session-tamper', 'Session token mismatch detected');
            }
        } catch(e) {}
    }, 30000);
}


// --- Sprint 482 — CSRF Protection ---
var _csrfToken = '';
function _initCSRFProtection() {
    _csrfToken = _generateSessionToken();
    try { sessionStorage.setItem('ms_csrf', _csrfToken); } catch(e) {}
    _injectCSRFHeaders();
}
function _injectCSRFHeaders() {
    var origFetch = window.fetch;
    window.fetch = function(url, options) {
        options = options || {};
        if (!options.headers) options.headers = {};
        if (typeof options.headers.append === 'function') options.headers.append('X-CSRF-Token', _csrfToken);
        else options.headers['X-CSRF-Token'] = _csrfToken;
        return origFetch.call(this, url, options);
    };
    var origXHR = XMLHttpRequest.prototype.open;
    XMLHttpRequest.prototype.open = function() {
        var xhr = this;
        var origSend = xhr.send;
        xhr.send = function() {
            try { xhr.setRequestHeader('X-CSRF-Token', _csrfToken); } catch(e) {}
            return origSend.apply(xhr, arguments);
        };
        return origXHR.apply(xhr, arguments);
    };
}


