// === Sprint 507-514 Feature 1: Progressive Jackpot ===
var _progressiveJackpot = { mini: 100, minor: 500, major: 5000, grand: 50000, lastUpdate: Date.now() };
function _loadJackpots() {
    var saved = JSON.parse(localStorage.getItem('ms_jackpots') || 'null');
    if (saved) _progressiveJackpot = saved;
}
function _saveJackpots() {
    _progressiveJackpot.lastUpdate = Date.now();
    localStorage.setItem('ms_jackpots', JSON.stringify(_progressiveJackpot));
}
function _tickJackpots(bet) {
    var contrib = bet * 0.02;
    _progressiveJackpot.mini += contrib * 0.4;
    _progressiveJackpot.minor += contrib * 0.3;
    _progressiveJackpot.major += contrib * 0.2;
    _progressiveJackpot.grand += contrib * 0.1;
    _saveJackpots();
    _updateJackpotDisplay();
}
function _checkJackpotWin() {
    var roll = Math.random();
    if (roll < 0.00001) return { type: 'grand', amount: _progressiveJackpot.grand };
    if (roll < 0.0001) return { type: 'major', amount: _progressiveJackpot.major };
    if (roll < 0.001) return { type: 'minor', amount: _progressiveJackpot.minor };
    if (roll < 0.005) return { type: 'mini', amount: _progressiveJackpot.mini };
    return null;
}
function _updateJackpotDisplay() {
    var el = document.getElementById('jackpot-ticker');
    if (!el) return;
    ['mini','minor','major','grand'].forEach(function(t) {
        var v = el.querySelector('[data-jp="' + t + '"]');
        if (v) v.textContent = '$' + _progressiveJackpot[t].toFixed(2);
    });
}
function _initProgressiveJackpot() {
    _loadJackpots();
    if (document.getElementById('jackpot-ticker')) return;
    var ticker = document.createElement('div');
    ticker.id = 'jackpot-ticker';
    ticker.className = 'jackpot-ticker';
    ticker.innerHTML = '<div class="jp-title">PROGRESSIVE JACKPOTS</div>' +
        '<div class="jp-row">' +
        '<div class="jp-item jp-grand"><span class="jp-name">GRAND</span><span class="jp-val" data-jp="grand">$' + _progressiveJackpot.grand.toFixed(2) + '</span></div>' +
        '<div class="jp-item jp-major"><span class="jp-name">MAJOR</span><span class="jp-val" data-jp="major">$' + _progressiveJackpot.major.toFixed(2) + '</span></div>' +
        '<div class="jp-item jp-minor"><span class="jp-name">MINOR</span><span class="jp-val" data-jp="minor">$' + _progressiveJackpot.minor.toFixed(2) + '</span></div>' +
        '<div class="jp-item jp-mini"><span class="jp-name">MINI</span><span class="jp-val" data-jp="mini">$' + _progressiveJackpot.mini.toFixed(2) + '</span></div>' +
        '</div>';
    document.body.prepend(ticker);
    setInterval(function() {
        _progressiveJackpot.mini += 0.01; _progressiveJackpot.minor += 0.03;
        _progressiveJackpot.major += 0.05; _progressiveJackpot.grand += 0.10;
        _updateJackpotDisplay();
    }, 3000);
    console.log('[Sprint 507-514] Progressive Jackpot ready');
}

/* ---- Feature 2: Bonus Wheel ---- */
function _initBonusWheel() {
    if (document.getElementById('bonus-wheel-btn')) return;
    var btn = document.createElement('button');
    btn.id = 'bonus-wheel-btn';
    btn.className = 'bonus-wheel-btn';
    btn.innerHTML = '\u2728 Bonus Wheel';
    btn.addEventListener('click', function() {
        var modal = document.createElement('div');
        modal.className = 'bonus-wheel-modal';
        modal.id = 'bonus-wheel-modal';
        var prizes = [50,100,200,25,500,75,150,1000,10,300];
        var colors = ['#ffd700','#ff6b6b','#4ecdc4','#45b7d1','#f9ca24','#6c5ce7','#fd79a8','#00b894','#e17055','#0984e3'];
        var canvas = '<canvas id="wheel-canvas" width="340" height="340"></canvas>';
        modal.innerHTML = '<div class="bw-inner">' +
            '<h3>\u2728 Bonus Wheel</h3>' +
            '<div class="bw-pointer">\u25BC</div>' +
            canvas +
            '<button id="wheel-spin-btn" class="bw-spin-btn">SPIN!</button>' +
            '<div id="wheel-result" class="bw-result"></div>' +
            '<button class="bw-close" onclick="document.getElementById(\&quot;bonus-wheel-modal\&quot;).remove()">Close</button>' +
            '</div>';
        document.body.appendChild(modal);
        var c = document.getElementById('wheel-canvas');
        var ctx = c.getContext('2d');
        var segments = prizes.length;
        var arc = 2 * Math.PI / segments;
        function drawWheel(rot) {
            ctx.clearRect(0,0,340,340);
            for (var i = 0; i < segments; i++) {
                ctx.beginPath();
                ctx.fillStyle = colors[i % colors.length];
                ctx.moveTo(170,170);
                ctx.arc(170,170,160, rot + i*arc, rot + (i+1)*arc);
                ctx.fill();
                ctx.save();
                ctx.translate(170,170);
                ctx.rotate(rot + i*arc + arc/2);
                ctx.fillStyle = '#fff';
                ctx.font = 'bold 14px Arial';
                ctx.textAlign = 'center';
                ctx.fillText('$'+prizes[i], 110, 5);
                ctx.restore();
            }
            ctx.beginPath();
            ctx.arc(170,170,20,0,2*Math.PI);
            ctx.fillStyle = '#333';
            ctx.fill();
        }
        drawWheel(0);
        document.getElementById('wheel-spin-btn').addEventListener('click', function() {
            this.disabled = true;
            var winner = Math.floor(Math.random() * segments);
            var totalRot = 4 * 2 * Math.PI + winner * arc + arc/2;
            var start = performance.now();
            var duration = 4000;
            function animate(now) {
                var elapsed = now - start;
                var progress = Math.min(elapsed / duration, 1);
                var ease = 1 - Math.pow(1 - progress, 3);
                drawWheel(ease * totalRot);
                if (progress < 1) requestAnimationFrame(animate);
                else {
                    document.getElementById('wheel-result').innerHTML = '\u2728 You won <b>$' + prizes[winner] + '</b>!';
                    var bal = parseFloat(localStorage.getItem('ms_balance') || '1000');
                    bal += prizes[winner];
                    localStorage.setItem('ms_balance', bal.toFixed(2));
                    if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
                    if (typeof _logAuditEvent === 'function') _logAuditEvent('bonus_wheel', { prize: prizes[winner] });
                }
            }
            requestAnimationFrame(animate);
        });
    });
    document.body.appendChild(btn);
    console.log('[Sprint 507-514] Bonus Wheel ready');
}

/* ---- Feature 3: Free Spins Round ---- */
var _freeSpinsState = { active: false, remaining: 0, totalWin: 0, multiplier: 1 };
function _triggerFreeSpins(count, mult) {
    _freeSpinsState = { active: true, remaining: count || 10, totalWin: 0, multiplier: mult || 2 };
    _showFreeSpinsOverlay();
    if (typeof _logAuditEvent === 'function') _logAuditEvent('free_spins_triggered', { count: count, multiplier: mult });
}
function _showFreeSpinsOverlay() {
    var existing = document.getElementById('freespin-overlay');
    if (existing) existing.remove();
    var overlay = document.createElement('div');
    overlay.id = 'freespin-overlay';
    overlay.className = 'freespin-overlay';
    overlay.innerHTML = '<div class="fs-banner">' +
        '<h2>\u2728 FREE SPINS!</h2>' +
        '<div class="fs-info">' +
        '<span>Remaining: <b id="fs-remaining">' + _freeSpinsState.remaining + '</b></span>' +
        '<span>Multiplier: <b id="fs-mult">x' + _freeSpinsState.multiplier + '</b></span>' +
        '<span>Total Win: <b id="fs-totalwin">$0.00</b></span>' +
        '</div></div>';
    document.body.appendChild(overlay);
    setTimeout(function() { overlay.classList.add('fs-minimized'); }, 3000);
}
function _updateFreeSpins(winAmount) {
    if (!_freeSpinsState.active) return;
    _freeSpinsState.totalWin += winAmount * _freeSpinsState.multiplier;
    _freeSpinsState.remaining--;
    var rem = document.getElementById('fs-remaining');
    var tw = document.getElementById('fs-totalwin');
    if (rem) rem.textContent = _freeSpinsState.remaining;
    if (tw) tw.textContent = '$' + _freeSpinsState.totalWin.toFixed(2);
    if (_freeSpinsState.remaining <= 0) {
        _freeSpinsState.active = false;
        var bal = parseFloat(localStorage.getItem('ms_balance') || '1000');
        bal += _freeSpinsState.totalWin;
        localStorage.setItem('ms_balance', bal.toFixed(2));
        if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
        setTimeout(function() {
            var ov = document.getElementById('freespin-overlay');
            if (ov) ov.innerHTML = '<div class="fs-complete"><h2>Free Spins Complete!</h2><p>Total Won: <b>$' + _freeSpinsState.totalWin.toFixed(2) + '</b></p></div>';
            setTimeout(function() { if (ov) ov.remove(); }, 4000);
        }, 1000);
    }
}
function _initFreeSpinsRound() {
    console.log('[Sprint 507-514] Free Spins Round ready');
}

/* ---- Feature 4: Multiplier Trail ---- */
var _multiplierTrail = { level: 0, multipliers: [1,1.5,2,3,5,8,10,15,25,50], consecutiveWins: 0 };
function _advanceMultiplierTrail() {
    _multiplierTrail.consecutiveWins++;
    if (_multiplierTrail.level < _multiplierTrail.multipliers.length - 1) {
        _multiplierTrail.level++;
    }
    _updateMultiplierTrailDisplay();
    return _multiplierTrail.multipliers[_multiplierTrail.level];
}
function _resetMultiplierTrail() {
    _multiplierTrail.level = 0;
    _multiplierTrail.consecutiveWins = 0;
    _updateMultiplierTrailDisplay();
}
function _updateMultiplierTrailDisplay() {
    var el = document.getElementById('mult-trail');
    if (!el) return;
    var html = '';
    _multiplierTrail.multipliers.forEach(function(m, i) {
        var cls = i === _multiplierTrail.level ? 'mt-active' : (i < _multiplierTrail.level ? 'mt-passed' : 'mt-future');
        html += '<span class="mt-step ' + cls + '">x' + m + '</span>';
    });
    el.innerHTML = html;
}
function _initMultiplierTrail() {
    if (document.getElementById('mult-trail')) return;
    var trail = document.createElement('div');
    trail.id = 'mult-trail';
    trail.className = 'mult-trail';
    document.body.appendChild(trail);
    _updateMultiplierTrailDisplay();
    console.log('[Sprint 507-514] Multiplier Trail ready');
}


