/* ---- Feature 2: Withdrawal Flow ---- */
function _initWithdrawalFlow() {
    if (document.getElementById('withdraw-btn')) return;
    var btn = document.createElement('button');
    btn.id = 'withdraw-btn';
    btn.className = 'withdraw-btn';
    btn.textContent = 'Withdraw';
    btn.addEventListener('click', function() {
        var bal = parseFloat(localStorage.getItem('ms_balance') || '0');
        var kyc = JSON.parse(localStorage.getItem('ms_kyc') || '{}');
        if (!kyc.verified) {
            alert('Please complete KYC verification before withdrawing.');
            return;
        }
        var modal = document.createElement('div');
        modal.className = 'withdraw-modal'; modal.id = 'withdraw-modal';
        modal.innerHTML = '<div class="wd-inner"><h3>Withdraw Funds</h3>' +
            '<p>Available Balance: <b>$' + bal.toFixed(2) + '</b></p>' +
            '<p>Minimum withdrawal: $20</p>' +
            '<label>Amount<input type="number" id="wd-amount" min="20" max="' + bal.toFixed(0) + '" placeholder="Enter amount"></label>' +
            '<label>Method<select id="wd-method"><option value="bank">Bank Transfer (1-3 days)</option><option value="crypto">Crypto (24 hrs)</option><option value="ewallet">E-Wallet (1-2 days)</option></select></label>' +
            '<label>Account/Address<input type="text" id="wd-account" placeholder="Your account details"></label>' +
            '<button id="wd-submit" class="wd-submit-btn">Request Withdrawal</button>' +
            '<div id="wd-result"></div>' +
            '<button class="wd-close" onclick="document.getElementById(\&quot;withdraw-modal\&quot;).remove()">Close</button>' +
            '</div>';
        document.body.appendChild(modal);
        document.getElementById('wd-submit').addEventListener('click', function() {
            var amount = parseFloat(document.getElementById('wd-amount').value);
            if (!amount || amount < 20) { alert('Minimum withdrawal is $20'); return; }
            if (amount > bal) { alert('Insufficient balance'); return; }
            bal -= amount;
            localStorage.setItem('ms_balance', bal.toFixed(2));
            if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
            var withdrawals = JSON.parse(localStorage.getItem('ms_withdrawals') || '[]');
            withdrawals.push({ amount: amount, method: document.getElementById('wd-method').value, account: document.getElementById('wd-account').value, ts: Date.now(), status: 'pending' });
            localStorage.setItem('ms_withdrawals', JSON.stringify(withdrawals));
            document.getElementById('wd-result').innerHTML = '<p class="wd-success">Withdrawal of $' + amount.toFixed(2) + ' requested! Processing time: 1-3 business days.</p>';
            if (typeof _logAuditEvent === 'function') _logAuditEvent('withdrawal_request', { amount: amount });
        });
    });
    document.body.appendChild(btn);
    console.log('[Sprint 515-522] Withdrawal Flow ready');
}

/* ---- Feature 3: Payment Method Manager ---- */
function _initPaymentMethods() {
    if (document.getElementById('payment-methods-panel')) return;
    var methods = JSON.parse(localStorage.getItem('ms_payment_methods') || '[]');
    var panel = document.createElement('div');
    panel.id = 'payment-methods-panel';
    panel.className = 'payment-methods-panel hidden';
    panel.innerHTML = '<div class="pm-inner"><h3>Payment Methods</h3>' +
        '<div id="pm-list" class="pm-list"></div>' +
        '<button id="pm-add" class="pm-add-btn">+ Add Payment Method</button>' +
        '<div id="pm-add-form" class="pm-add-form hidden">' +
        '<select id="pm-type"><option value="card">Credit/Debit Card</option><option value="bank">Bank Account</option><option value="crypto">Cryptocurrency</option></select>' +
        '<input type="text" id="pm-name" placeholder="Nickname (e.g. My Visa)">' +
        '<input type="text" id="pm-details" placeholder="Last 4 digits or address">' +
        '<button id="pm-save" class="pm-save-btn">Save</button>' +
        '</div></div>';
    document.body.appendChild(panel);
    function renderMethods() {
        var list = document.getElementById('pm-list');
        methods = JSON.parse(localStorage.getItem('ms_payment_methods') || '[]');
        if (methods.length === 0) { list.innerHTML = '<p>No payment methods saved.</p>'; return; }
        list.innerHTML = methods.map(function(m, i) {
            return '<div class="pm-item"><span class="pm-icon">' + (m.type==='card'?'Card':m.type==='bank'?'Bank':'Crypto') + '</span><span>' + m.name + '</span><span>***' + m.details + '</span><button class="pm-remove" data-idx="' + i + '">Remove</button></div>';
        }).join('');
        list.querySelectorAll('.pm-remove').forEach(function(b) {
            b.addEventListener('click', function() {
                methods.splice(parseInt(this.dataset.idx), 1);
                localStorage.setItem('ms_payment_methods', JSON.stringify(methods));
                renderMethods();
            });
        });
    }
    renderMethods();
    document.getElementById('pm-add').addEventListener('click', function() {
        document.getElementById('pm-add-form').classList.toggle('hidden');
    });
    document.getElementById('pm-save').addEventListener('click', function() {
        var type = document.getElementById('pm-type').value;
        var name = document.getElementById('pm-name').value;
        var details = document.getElementById('pm-details').value;
        if (!name || !details) { alert('Please fill all fields'); return; }
        methods.push({ type: type, name: name, details: details, added: Date.now() });
        localStorage.setItem('ms_payment_methods', JSON.stringify(methods));
        renderMethods();
        document.getElementById('pm-add-form').classList.add('hidden');
    });
    console.log('[Sprint 515-522] Payment Methods ready');
}

