// === Sprint 515-522 Feature 5: Currency Converter ===
var _currencyRates = { USD: 1, EUR: 0.92, GBP: 0.79, CAD: 1.36, AUD: 1.53, JPY: 149.5, BTC: 0.000015, ETH: 0.00029 };
function _initCurrencyConverter() {
    if (document.getElementById('currency-converter')) return;
    var conv = document.createElement('div');
    conv.id = 'currency-converter';
    conv.className = 'currency-converter hidden';
    var opts = '';
    Object.keys(_currencyRates).forEach(function(c) { opts += '<option value="' + c + '">' + c + '</option>'; });
    conv.innerHTML = '<div class="cc-inner"><h3>Currency Converter</h3>' +
        '<div class="cc-row"><input type="number" id="cc-amount" value="100" min="0"><select id="cc-from">' + opts + '</select></div>' +
        '<div class="cc-arrow">&#8595;</div>' +
        '<div class="cc-row"><span id="cc-result" class="cc-result">--</span><select id="cc-to">' + opts.replace('value="EUR"', 'value="EUR" selected') + '</select></div>' +
        '<p class="cc-note">Rates are approximate. Actual conversion at time of transaction.</p></div>';
    document.body.appendChild(conv);
    function convert() {
        var amt = parseFloat(document.getElementById('cc-amount').value) || 0;
        var from = document.getElementById('cc-from').value;
        var to = document.getElementById('cc-to').value;
        var usd = amt / _currencyRates[from];
        var result = usd * _currencyRates[to];
        document.getElementById('cc-result').textContent = result.toFixed(to==='BTC'||to==='ETH'?6:2) + ' ' + to;
    }
    document.getElementById('cc-amount').addEventListener('input', convert);
    document.getElementById('cc-from').addEventListener('change', convert);
    document.getElementById('cc-to').addEventListener('change', convert);
    convert();
    console.log('[Sprint 515-522] Currency Converter ready');
}

/* ---- Feature 6: Spending Alerts ---- */
function _initSpendingAlerts() {
    var alerts = JSON.parse(localStorage.getItem('ms_spending_alerts') || '{"daily":100,"weekly":500,"monthly":2000}');
    var spending = JSON.parse(localStorage.getItem('ms_spending_tracking') || '{"daily":0,"weekly":0,"monthly":0,"lastReset":0}');
    var now = Date.now();
    if (now - spending.lastReset > 86400000) { spending.daily = 0; spending.lastReset = now; }
    localStorage.setItem('ms_spending_tracking', JSON.stringify(spending));
    if (spending.daily > alerts.daily * 0.8) {
        var warn = document.createElement('div');
        warn.className = 'spending-alert';
        warn.innerHTML = 'You have spent $' + spending.daily.toFixed(2) + ' today (limit: $' + alerts.daily + '). Consider taking a break.';
        document.body.appendChild(warn);
        setTimeout(function() { warn.remove(); }, 8000);
    }
    console.log('[Sprint 515-522] Spending Alerts ready');
}

