function _initDailyChallenges() {
    if (document.getElementById('daily-challenges')) return;
    var today = new Date().toISOString().slice(0,10);
    var challenges = JSON.parse(localStorage.getItem('ms_daily_challenges') || '{}');
    if (challenges.date !== today) {
        challenges = { date: today, items: [
            {id:'spin20',name:'Spin Master',desc:'Complete 20 spins',target:20,progress:0,reward:25},
            {id:'win5',name:'Winner',desc:'Win 5 times',target:5,progress:0,reward:50},
            {id:'wager100',name:'High Stakes',desc:'Wager $100',target:100,progress:0,reward:30},
            {id:'bonus1',name:'Bonus Hunter',desc:'Trigger 1 bonus round',target:1,progress:0,reward:40}
        ]};
        localStorage.setItem('ms_daily_challenges', JSON.stringify(challenges));
    }
    var panel = document.createElement('div');
    panel.id = 'daily-challenges';
    panel.className = 'daily-challenges hidden';
    var html = '<div class="dc-inner"><h3>Daily Challenges</h3><div class="dc-timer">Resets at midnight</div>';
    challenges.items.forEach(function(c) {
        var pct = Math.min(100, (c.progress/c.target)*100);
        var done = c.progress >= c.target;
        html += '<div class="dc-item'+(done?' dc-done':'')+'"><div class="dc-info"><span class="dc-name">'+c.name+'</span><span class="dc-desc">'+c.desc+'</span></div><div class="dc-bar"><div class="dc-fill" style="width:'+pct+'%"></div></div><span class="dc-reward">'+(done?'Claimed':'$'+c.reward)+'</span></div>';
    });
    html += '</div>';
    panel.innerHTML = html;
    document.body.appendChild(panel);
    console.log('[Sprint 523-530] Daily Challenges ready');
}

