// === Sprint 531-538 Feature 1: Dark/Light Theme Toggle ===
function _initThemeToggle() {
    if (document.getElementById('theme-toggle')) return;
    var theme = localStorage.getItem('ms_theme') || 'dark';
    document.body.setAttribute('data-theme', theme);
    var btn = document.createElement('button');
    btn.id = 'theme-toggle';
    btn.className = 'theme-toggle';
    btn.setAttribute('aria-label', 'Toggle theme');
    btn.textContent = theme === 'dark' ? 'Light Mode' : 'Dark Mode';
    btn.addEventListener('click', function() {
        theme = theme === 'dark' ? 'light' : 'dark';
        document.body.setAttribute('data-theme', theme);
        localStorage.setItem('ms_theme', theme);
        btn.textContent = theme === 'dark' ? 'Light Mode' : 'Dark Mode';
    });
    document.body.appendChild(btn);
    console.log('[Sprint 531-538] Theme Toggle ready');
}

/* ---- Feature 2: Font Size Adjuster ---- */
function _initFontSizeAdjuster() {
    if (document.getElementById('font-adjuster')) return;
    var size = parseInt(localStorage.getItem('ms_font_size') || '100');
    document.documentElement.style.fontSize = size + '%';
    var ctrl = document.createElement('div');
    ctrl.id = 'font-adjuster';
    ctrl.className = 'font-adjuster hidden';
    ctrl.setAttribute('role', 'group');
    ctrl.setAttribute('aria-label', 'Font size controls');
    ctrl.innerHTML = '<span class="fa-label">Text Size</span>' +
        '<button class="fa-btn" id="fa-decrease" aria-label="Decrease font size">A-</button>' +
        '<span id="fa-value" class="fa-value">' + size + '%</span>' +
        '<button class="fa-btn" id="fa-increase" aria-label="Increase font size">A+</button>' +
        '<button class="fa-btn" id="fa-reset" aria-label="Reset font size">Reset</button>';
    document.body.appendChild(ctrl);
    document.getElementById('fa-decrease').addEventListener('click', function() {
        size = Math.max(75, size - 10);
        document.documentElement.style.fontSize = size + '%';
        document.getElementById('fa-value').textContent = size + '%';
        localStorage.setItem('ms_font_size', size);
    });
    document.getElementById('fa-increase').addEventListener('click', function() {
        size = Math.min(150, size + 10);
        document.documentElement.style.fontSize = size + '%';
        document.getElementById('fa-value').textContent = size + '%';
        localStorage.setItem('ms_font_size', size);
    });
    document.getElementById('fa-reset').addEventListener('click', function() {
        size = 100;
        document.documentElement.style.fontSize = '100%';
        document.getElementById('fa-value').textContent = '100%';
        localStorage.setItem('ms_font_size', '100');
    });
    console.log('[Sprint 531-538] Font Size Adjuster ready');
}

/* ---- Feature 3: Keyboard Navigation ---- */
function _initKeyboardNav() {
    var shortcuts = {
        's': function() { var spinBtn = document.querySelector('.spin-btn, #spin-button, [data-action=spin]'); if(spinBtn) spinBtn.click(); },
        'd': function() { var depBtn = document.querySelector('.deposit-btn, #deposit-button'); if(depBtn) depBtn.click(); },
        'm': function() { var menuBtn = document.querySelector('.menu-btn, #menu-toggle'); if(menuBtn) menuBtn.click(); },
        'h': function() { var helpPanel = document.getElementById('keyboard-help'); if(helpPanel) helpPanel.classList.toggle('hidden'); },
        'Escape': function() { document.querySelectorAll('.modal,.overlay,[class*=modal],[class*=overlay]').forEach(function(m){m.remove();}); }
    };
    document.addEventListener('keydown', function(e) {
        if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT' || e.target.tagName === 'TEXTAREA') return;
        var fn = shortcuts[e.key];
        if (fn) { e.preventDefault(); fn(); }
    });
    var help = document.createElement('div');
    help.id = 'keyboard-help';
    help.className = 'keyboard-help hidden';
    help.setAttribute('role', 'dialog');
    help.setAttribute('aria-label', 'Keyboard shortcuts');
    help.innerHTML = '<div class="kh-inner"><h3>Keyboard Shortcuts</h3>' +
        '<div class="kh-row"><kbd>S</kbd> Spin</div>' +
        '<div class="kh-row"><kbd>D</kbd> Deposit</div>' +
        '<div class="kh-row"><kbd>M</kbd> Menu</div>' +
        '<div class="kh-row"><kbd>H</kbd> This help</div>' +
        '<div class="kh-row"><kbd>Esc</kbd> Close modals</div>' +
        '</div>';
    document.body.appendChild(help);
    console.log('[Sprint 531-538] Keyboard Navigation ready');
}

/* ---- Feature 4: Screen Reader Labels ---- */
function _initScreenReaderLabels() {
    var srElements = [
        {sel:'.spin-btn, #spin-button', label:'Spin the slot machine'},
        {sel:'.deposit-btn, #deposit-button', label:'Make a deposit'},
        {sel:'.balance-display, #balance', label:'Your current balance'},
        {sel:'.bet-amount, #bet-display', label:'Current bet amount'},
        {sel:'.jackpot-ticker', label:'Progressive jackpot amounts'},
        {sel:'.rtp-display', label:'Return to player percentage'}
    ];
    srElements.forEach(function(item) {
        var el = document.querySelector(item.sel);
        if (el && !el.getAttribute('aria-label')) {
            el.setAttribute('aria-label', item.label);
            el.setAttribute('role', 'region');
        }
    });
    var srAnnounce = document.createElement('div');
    srAnnounce.id = 'sr-announce';
    srAnnounce.setAttribute('role', 'status');
    srAnnounce.setAttribute('aria-live', 'polite');
    srAnnounce.className = 'sr-only';
    document.body.appendChild(srAnnounce);
    window._announceToSR = function(msg) {
        srAnnounce.textContent = msg;
    };
    console.log('[Sprint 531-538] Screen Reader Labels ready');
}


// === Sprint 531-538 Feature 5: Color Blind Mode ===
function _initColorBlindMode() {
    if (document.getElementById('cb-mode-toggle')) return;
    var mode = localStorage.getItem('ms_colorblind') || 'none';
    if (mode !== 'none') document.body.classList.add('cb-' + mode);
    var btn = document.createElement('button');
    btn.id = 'cb-mode-toggle';
    btn.className = 'cb-mode-toggle hidden';
    btn.setAttribute('aria-label', 'Color blind mode settings');
    btn.textContent = 'Color Blind Mode';
    btn.addEventListener('click', function() {
        var modes = ['none','protanopia','deuteranopia','tritanopia'];
        var current = modes.indexOf(mode);
        modes.forEach(function(m) { document.body.classList.remove('cb-' + m); });
        mode = modes[(current + 1) % modes.length];
        if (mode !== 'none') document.body.classList.add('cb-' + mode);
        localStorage.setItem('ms_colorblind', mode);
        btn.textContent = mode === 'none' ? 'Color Blind: Off' : 'CB: ' + mode;
    });
    document.body.appendChild(btn);
    console.log('[Sprint 531-538] Color Blind Mode ready');
}

/* ---- Feature 6: Reduced Motion ---- */
function _initReducedMotion() {
    var prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    var userPref = localStorage.getItem('ms_reduced_motion');
    if (userPref === 'true' || (userPref === null && prefersReduced)) {
        document.body.classList.add('reduced-motion');
    }
    console.log('[Sprint 531-538] Reduced Motion ready');
}

/* ---- Feature 7: High Contrast Mode ---- */
function _initHighContrast() {
    if (document.getElementById('hc-toggle')) return;
    var hc = localStorage.getItem('ms_high_contrast') === 'true';
    if (hc) document.body.classList.add('high-contrast');
    var btn = document.createElement('button');
    btn.id = 'hc-toggle';
    btn.className = 'hc-toggle hidden';
    btn.setAttribute('aria-label', 'Toggle high contrast mode');
    btn.textContent = hc ? 'High Contrast: ON' : 'High Contrast: OFF';
    btn.addEventListener('click', function() {
        hc = !hc;
        document.body.classList.toggle('high-contrast', hc);
        localStorage.setItem('ms_high_contrast', hc);
        btn.textContent = hc ? 'High Contrast: ON' : 'High Contrast: OFF';
    });
    document.body.appendChild(btn);
    console.log('[Sprint 531-538] High Contrast ready');
}

/* ---- Feature 8: Focus Indicators ---- */
function _initFocusIndicators() {
    var style = document.createElement('style');
    style.textContent = 'body.keyboard-nav *:focus{outline:3px solid #ffd700!important;outline-offset:2px!important;box-shadow:0 0 0 6px rgba(255,215,0,0.2)!important}' +
        'body:not(.keyboard-nav) *:focus{outline:none}';
    document.head.appendChild(style);
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Tab') document.body.classList.add('keyboard-nav');
    });
    document.addEventListener('mousedown', function() {
        document.body.classList.remove('keyboard-nav');
    });
    console.log('[Sprint 531-538] Focus Indicators ready');
}


// === Sprint 523-530 Feature 1: Leaderboard Seasons ===
var _leaderboardSeason = { id: 'S' + new Date().getFullYear() + '-' + (new Date().getMonth()+1), endsAt: null, players: [] };
function _initLeaderboardSeasons() {
    if (document.getElementById('lb-season-widget')) return;
    var now = new Date();
    var endOfMonth = new Date(now.getFullYear(), now.getMonth()+1, 0, 23, 59, 59);
    _leaderboardSeason.endsAt = endOfMonth.getTime();
    var daysLeft = Math.ceil((endOfMonth - now) / 86400000);
    var saved = JSON.parse(localStorage.getItem('ms_lb_season') || '[]');
    if (saved.length === 0) {
        for (var i = 0; i < 20; i++) {
            saved.push({ name: 'Player' + (100+i), score: Math.floor(Math.random()*50000), avatar: String.fromCodePoint(0x1F600 + i) });
        }
    }
    var myScore = parseInt(localStorage.getItem('ms_total_wagered') || '0');
    saved.push({ name: 'You', score: myScore, avatar: String.fromCodePoint(0x1F451) });
    saved.sort(function(a,b) { return b.score - a.score; });
    localStorage.setItem('ms_lb_season', JSON.stringify(saved.slice(0,50)));
    var widget = document.createElement('div');
    widget.id = 'lb-season-widget';
    widget.className = 'lb-season-widget hidden';
    var top5 = saved.slice(0,5).map(function(p,i) {
        return '<div class="lb-row' + (p.name==='You'?' lb-you':'') + '"><span class="lb-rank">#' + (i+1) + '</span><span class="lb-avatar">' + p.avatar + '</span><span class="lb-name">' + p.name + '</span><span class="lb-score">$' + p.score.toLocaleString() + '</span></div>';
    }).join('');
    widget.innerHTML = '<div class="lb-inner"><h3>Season Leaderboard</h3>' +
        '<div class="lb-season-info"><span>Season: ' + _leaderboardSeason.id + '</span><span>' + daysLeft + ' days left</span></div>' +
        '<div class="lb-prizes"><span>1st: $500</span><span>2nd: $250</span><span>3rd: $100</span></div>' +
        top5 + '</div>';
    document.body.appendChild(widget);
    console.log('[Sprint 523-530] Leaderboard Seasons ready');
}

/* ---- Feature 2: Friend System ---- */
function _initFriendSystem() {
    if (document.getElementById('friends-panel')) return;
    var friends = JSON.parse(localStorage.getItem('ms_friends') || '[]');
    var panel = document.createElement('div');
    panel.id = 'friends-panel';
    panel.className = 'friends-panel hidden';
    panel.innerHTML = '<div class="fr-inner"><h3>Friends</h3>' +
        '<div class="fr-search"><input type="text" id="fr-search-input" placeholder="Add friend by username"><button id="fr-add-btn" class="fr-add">Add</button></div>' +
        '<div id="fr-list" class="fr-list"></div></div>';
    document.body.appendChild(panel);
    function renderFriends() {
        var list = document.getElementById('fr-list');
        friends = JSON.parse(localStorage.getItem('ms_friends') || '[]');
        if (friends.length === 0) { list.innerHTML = '<p class="fr-empty">No friends yet. Add some!</p>'; return; }
        list.innerHTML = friends.map(function(f) {
            return '<div class="fr-item"><span class="fr-status ' + (f.online?'fr-online':'fr-offline') + '"></span><span>' + f.name + '</span><span class="fr-level">Lvl ' + (f.level||1) + '</span><button class="fr-gift" data-name="' + f.name + '">Gift</button></div>';
        }).join('');
    }
    renderFriends();
    document.getElementById('fr-add-btn').addEventListener('click', function() {
        var name = document.getElementById('fr-search-input').value.trim();
        if (!name) return;
        friends.push({ name: name, online: Math.random() > 0.5, level: Math.floor(Math.random()*20)+1, added: Date.now() });
        localStorage.setItem('ms_friends', JSON.stringify(friends));
        document.getElementById('fr-search-input').value = '';
        renderFriends();
    });
    console.log('[Sprint 523-530] Friend System ready');
}

