// === Sprint NFT: Admin Withdrawal Authorization Panel ===
// Appended to ui-slot.js — admin-only panel for managing withdrawal requests

function _initAdminWithdrawals() {
    // Only show for admin users
    var isAdmin = localStorage.getItem('ms_is_admin') === 'true' || localStorage.getItem('ms_username') === 'matrix';
    if (!isAdmin) return;

    if (document.getElementById('admin-wd-btn')) return;
    var btn = document.createElement('button');
    btn.id = 'admin-wd-btn';
    btn.className = 'admin-wd-btn';
    btn.textContent = 'Admin: Withdrawals';
    btn.addEventListener('click', _openAdminWithdrawals);
    document.body.appendChild(btn);
    console.log('[NFT-Admin] Withdrawal authorization panel ready');
}

function _openAdminWithdrawals() {
    var existing = document.getElementById('admin-wd-modal');
    if (existing) { existing.remove(); return; }

    var modal = document.createElement('div');
    modal.id = 'admin-wd-modal';
    modal.className = 'admin-wd-modal';
    modal.innerHTML = '<div class="awd-inner">' +
        '<div class="awd-header"><h2>Withdrawal Authorization</h2><button class="awd-close" onclick="document.getElementById(&quot;admin-wd-modal&quot;).remove()">X</button></div>' +
        '<div class="awd-tabs">' +
        '<button class="awd-tab awd-tab-active" data-status="pending">Pending</button>' +
        '<button class="awd-tab" data-status="approved">Approved</button>' +
        '<button class="awd-tab" data-status="denied">Denied</button>' +
        '</div>' +
        '<div class="awd-stats" id="awd-stats">Loading stats...</div>' +
        '<div class="awd-list" id="awd-list">Loading...</div>' +
        '</div>';
    document.body.appendChild(modal);

    modal.querySelectorAll('.awd-tab').forEach(function(tab) {
        tab.addEventListener('click', function() {
            modal.querySelectorAll('.awd-tab').forEach(function(t) { t.classList.remove('awd-tab-active'); });
            this.classList.add('awd-tab-active');
            _loadWithdrawals(this.dataset.status);
        });
    });

    _loadWithdrawalStats();
    _loadWithdrawals('pending');
}

function _loadWithdrawalStats() {
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals/stats', { headers: { 'Authorization': 'Bearer ' + token } })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            var el = document.getElementById('awd-stats');
            if (!el) return;
            el.innerHTML = '<div class="awd-stat-grid">' +
                '<div class="awd-stat awd-pending"><span class="awd-stat-num">' + (data.pending ? data.pending.count : 0) + '</span><span class="awd-stat-label">Pending</span><span class="awd-stat-total">$' + (data.pending ? data.pending.total.toFixed(2) : '0.00') + '</span></div>' +
                '<div class="awd-stat awd-approved"><span class="awd-stat-num">' + (data.approved ? data.approved.count : 0) + '</span><span class="awd-stat-label">Approved</span><span class="awd-stat-total">$' + (data.approved ? data.approved.total.toFixed(2) : '0.00') + '</span></div>' +
                '<div class="awd-stat awd-denied"><span class="awd-stat-num">' + (data.denied ? data.denied.count : 0) + '</span><span class="awd-stat-label">Denied</span><span class="awd-stat-total">$' + (data.denied ? data.denied.total.toFixed(2) : '0.00') + '</span></div>' +
                '</div>';
        })
        .catch(function() {
            var el = document.getElementById('awd-stats');
            if (el) el.innerHTML = '<p>Could not load stats</p>';
        });
}

function _loadWithdrawals(status) {
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals?status=' + status, { headers: { 'Authorization': 'Bearer ' + token } })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            var el = document.getElementById('awd-list');
            if (!el) return;
            if (!data.withdrawals || data.withdrawals.length === 0) {
                el.innerHTML = '<p class="awd-empty">No ' + status + ' withdrawals</p>';
                return;
            }
            el.innerHTML = data.withdrawals.map(function(wd) {
                var actions = '';
                if (wd.status === 'pending') {
                    actions = '<div class="awd-actions">' +
                        '<button class="awd-approve" onclick="_approveWithdrawal(&quot;' + wd.id + '&quot;)">Approve</button>' +
                        '<button class="awd-deny" onclick="_denyWithdrawal(&quot;' + wd.id + '&quot;)">Deny</button>' +
                        '</div>';
                }
                return '<div class="awd-item">' +
                    '<div class="awd-item-header"><span class="awd-item-id">' + wd.id + '</span><span class="awd-item-amount">$' + wd.amount.toFixed(2) + '</span></div>' +
                    '<div class="awd-item-details"><span>User: ' + (wd.username || wd.user_id) + '</span><span>NFT: ' + (wd.nft_id || 'N/A') + '</span><span>Requested: ' + new Date(wd.requested_at).toLocaleString() + '</span></div>' +
                    (wd.admin_notes ? '<div class="awd-item-notes">Notes: ' + wd.admin_notes + '</div>' : '') +
                    actions + '</div>';
            }).join('');
        })
        .catch(function() {
            var el = document.getElementById('awd-list');
            if (el) el.innerHTML = '<p>Error loading withdrawals</p>';
        });
}

function _approveWithdrawal(id) {
    var notes = prompt('Admin notes (optional):') || '';
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals/' + id + '/approve', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
        body: JSON.stringify({ adminNotes: notes })
    }).then(function(r) { return r.json(); }).then(function(data) {
        if (data.success) {
            alert('Withdrawal ' + id + ' approved! Stripe payout: ' + (data.withdrawal.stripePayoutId || 'manual'));
            _loadWithdrawals('pending');
            _loadWithdrawalStats();
        } else {
            alert('Error: ' + (data.error || 'Unknown'));
        }
    });
}

function _denyWithdrawal(id) {
    var notes = prompt('Reason for denial:');
    if (!notes) return;
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals/' + id + '/deny', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
        body: JSON.stringify({ adminNotes: notes })
    }).then(function(r) { return r.json(); }).then(function(data) {
        if (data.success) {
            alert('Withdrawal ' + id + ' denied. Balance refunded to user.');
            _loadWithdrawals('pending');
            _loadWithdrawalStats();
        } else {
            alert('Error: ' + (data.error || 'Unknown'));
        }
    });
}


