/* ---- Feature 8: Comeback Detection ---- */
var _comebackState555 = { lastSeen: 0, totalLosses: 0, triggered: false };
function _initComebackDetection555() {
    var saved = JSON.parse(localStorage.getItem('ms_comeback555') || 'null');
    if (saved) _comebackState555 = saved;
    var now = Date.now();
    var lastSeen = _comebackState555.lastSeen || 0;
    var hoursSinceLastVisit = (now - lastSeen) / 3600000;
    if (hoursSinceLastVisit > 24 && lastSeen > 0 && !_comebackState555.triggered) {
        _showComebackOffer555(hoursSinceLastVisit);
        _comebackState555.triggered = true;
    }
    _comebackState555.lastSeen = now;
    localStorage.setItem('ms_comeback555', JSON.stringify(_comebackState555));
    console.log('[Sprint 555-562] Comeback Detection ready');
}
function _showComebackOffer555(hours) {
    var bonus = hours > 168 ? 100 : hours > 72 ? 50 : 25;
    var overlay = document.createElement('div');
    overlay.id = 'comeback-offer-555';
    overlay.className = 'comeback-overlay555';
    overlay.innerHTML = '<div class="comeback-inner555">' +
        '<h2>Welcome Back!</h2>' +
        '<p>We missed you! It has been ' + Math.floor(hours) + ' hours since your last visit.</p>' +
        '<div class="comeback-bonus555">$' + bonus + ' Bonus Credits</div>' +
        '<button class="comeback-claim555" onclick="_claimComebackBonus555(' + bonus + ')">Claim Bonus</button>' +
        '<button class="comeback-skip555" onclick="document.getElementById(&quot;comeback-offer-555&quot;).remove()">Maybe Later</button>' +
        '</div>';
    document.body.appendChild(overlay);
}
function _claimComebackBonus555(amount) {
    var bal = parseFloat(localStorage.getItem('ms_balance') || '1000');
    bal += amount;
    localStorage.setItem('ms_balance', bal.toFixed(2));
    if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
    _comebackState555.triggered = true;
    _comebackState555.totalLosses = 0;
    localStorage.setItem('ms_comeback555', JSON.stringify(_comebackState555));
    document.getElementById('comeback-offer-555').remove();
    if (typeof _addXP === 'function') _addXP(15);
}


