/* ===== Sprint 571-578: Mobile Optimization & UX Polish ===== */

/* ---- Feature 1: Touch Gesture Controls ---- */
var _touchGestures571 = { startX: 0, startY: 0, active: false };
function _initTouchGestures() {
    var gameArea = document.getElementById('game-area') || document.getElementById('slot-container') || document.body;
    gameArea.addEventListener('touchstart', function(e) {
        _touchGestures571.startX = e.touches[0].clientX;
        _touchGestures571.startY = e.touches[0].clientY;
        _touchGestures571.active = true;
    }, { passive: true });
    gameArea.addEventListener('touchend', function(e) {
        if (!_touchGestures571.active) return;
        _touchGestures571.active = false;
        var dx = e.changedTouches[0].clientX - _touchGestures571.startX;
        var dy = e.changedTouches[0].clientY - _touchGestures571.startY;
        if (Math.abs(dx) > 80 && Math.abs(dx) > Math.abs(dy)) {
            if (dx > 0) { /* swipe right - next game */ if (typeof nextGame === 'function') nextGame(); }
            else { /* swipe left - prev game */ if (typeof prevGame === 'function') prevGame(); }
        }
        if (dy < -80 && Math.abs(dy) > Math.abs(dx)) {
            /* swipe up - quick spin */
            if (typeof spinReels === 'function') spinReels();
        }
    }, { passive: true });
    console.log('[Sprint 571-578] Touch Gestures ready');
}

/* ---- Feature 2: Responsive Layout Manager ---- */
