/* ---- Feature 2: Balance Warning System ---- */
var _balanceWarning587 = { thresholds: [50, 20, 10, 5], lastWarning: 0 };
function _initBalanceWarning() {
    console.log('[Sprint 587-594] Balance Warning ready');
}
function _checkBalanceWarning(currentBalance) {
    if (!currentBalance && currentBalance !== 0) return;
    var now = Date.now();
    if (now - _balanceWarning587.lastWarning < 60000) return;
    for (var i = 0; i < _balanceWarning587.thresholds.length; i++) {
        var threshold = _balanceWarning587.thresholds[i];
        if (currentBalance <= threshold && currentBalance > 0) {
            _balanceWarning587.lastWarning = now;
            _showBalanceWarning587(currentBalance, threshold);
            break;
        }
    }
}
function _showBalanceWarning587(balance, threshold) {
    if (typeof _showNotification571 === 'function') {
        var msg = balance <= 5 ? 'Very low balance! Only $' + balance.toFixed(2) + ' remaining.' :
                  balance <= 10 ? 'Low balance warning: $' + balance.toFixed(2) : 
                  'Balance getting low: $' + balance.toFixed(2);
        _showNotification571(msg, balance <= 10 ? 'error' : 'warning', 5000);
    }
    if (balance <= 10) {
        setTimeout(function() { _showQuickDeposit(balance <= 5 ? 10 : 25); }, 2000);
    }
}

