function _predictBalance611() {
    var trend = _trendData611.slice(-20);
    if (trend.length < 5) return null;
    var netPerSpin = 0;
    for (var i = 0; i < trend.length; i++) {
        netPerSpin += trend[i].win ? trend[i].amount : -trend[i].amount;
    }
    netPerSpin /= trend.length;
    var currentBal = parseFloat(localStorage.getItem('ms_balance') || '0');
    var spinsToZero = netPerSpin < 0 ? Math.floor(currentBal / Math.abs(netPerSpin)) : Infinity;
    if (spinsToZero < 20 && spinsToZero > 0) {
        if (typeof _showNotification571 === 'function') _showNotification571('At current rate, your balance may run out in ~' + spinsToZero + ' spins. Consider adjusting your bet.', 'warning', 6000);
    }
    return { netPerSpin: netPerSpin, spinsToZero: spinsToZero };
}

