// ═══════════════════════════════════════════════════════
// QA-TOOLS MODULE
// ═══════════════════════════════════════════════════════


        function applyUrlDebugConfig() {
            const params = new URLSearchParams(window.location.search);

            const seedParam = params.get('spinSeed');
            if (seedParam) {
                setDeterministicSeed(seedParam);
            }

            const forceSpinParam = params.get('forceSpin');
            if (forceSpinParam) {
                queueForcedSpin(forceSpinParam);
            }

            const forceOutcomeParam = params.get('forceOutcome');
            if (forceOutcomeParam) {
                queueForcedOutcome(forceOutcomeParam, params.get('forceSymbol'));
            }

            const qaToolsParam = params.get('qaTools');
            if (qaToolsParam === '1' || qaToolsParam === 'true') {
                // Show the QA container (may be hidden via inline style for production)
                const qaContainer = getQaNode('qaTools');
                if (qaContainer) qaContainer.style.display = '';
                setQaToolsExpanded(true);
            }

            const qaResetClearSeedParam = params.get('qaResetClearSeed');
            if (qaResetClearSeedParam === '1' || qaResetClearSeedParam === 'true') {
                const clearSeedToggle = getQaNode('qaResetClearSeed');
                if (clearSeedToggle) {
                    clearSeedToggle.checked = true;
                }
            }

            const openSlotId = params.get('openSlot');
            const openTarget = games.find((game) => game.id === openSlotId);
            if (openTarget) {
                openSlot(openTarget.id);
            }

            const autoSpinValue = params.get('autoSpin');
            if ((autoSpinValue === '1' || autoSpinValue === 'true') && openTarget) {
                const delayParam = Number.parseInt(params.get('autoSpinDelay') || '700', 10);
                const delay = Number.isFinite(delayParam) ? Math.max(0, delayParam) : 700;
                setTimeout(() => {
                    if (currentGame && !spinning) {
                        spin();
                    }
                }, delay);
            }

            refreshQaStateDisplay();
        }


        function getDebugState() {
            return {
                deterministicMode: Boolean(deterministicRng),
                deterministicSeed,
                queuedForcedSpins: forcedSpinQueue.map((symbols) => [...symbols]),
                availableSymbols: [...SLOT_SYMBOLS]
            };
        }


        function getQaNode(id) {
            return document.getElementById(id);
        }


        function setQaStatus(text, type = 'info') {
            const statusEl = getQaNode('qaStatusLine');
            if (!statusEl) return;

            statusEl.textContent = text || '';
            statusEl.className = 'qa-status';

            if (type === 'good') {
                statusEl.classList.add('qa-status-good');
            } else if (type === 'warn') {
                statusEl.classList.add('qa-status-warn');
            } else if (type === 'error') {
                statusEl.classList.add('qa-status-error');
            }
        }


        function setQaToolsExpanded(expanded) {
            qaToolsOpen = Boolean(expanded);
            const container = getQaNode('qaTools');
            const bodyEl = getQaNode('qaToolsBody');
            const toggleBtn = getQaNode('qaToggleBtn');

            // Ensure the QA container is visible when expanding
            if (container && qaToolsOpen) {
                container.style.display = '';
            }
            if (bodyEl) {
                bodyEl.classList.toggle('active', qaToolsOpen);
            }
            if (toggleBtn) {
                toggleBtn.textContent = qaToolsOpen ? 'Hide' : 'Show';
            }
        }


        function refreshQaStateDisplay() {
            const lineEl = getQaNode('qaStateLine');
            if (!lineEl) return;
            const state = getDebugState();
            const seedLabel = state.deterministicMode ? `seed=${state.deterministicSeed}` : 'seed=off';
            lineEl.textContent = `${seedLabel} | queued=${state.queuedForcedSpins.length}`;
        }


        function resetSessionState(options = {}) {
            if (spinning) return false;

            const config = {
                clearDeterministic: false,
                clearQueue: true,
                ...options
            };

            balance = DEFAULT_BALANCE;
            stats = createDefaultStats();
            lastMessage = { type: 'info', text: '' };

            // Clear free spins state
            freeSpinsActive = false;
            freeSpinsRemaining = 0;
            freeSpinsTotalWin = 0;
            freeSpinsMultiplier = 1;
            freeSpinsCascadeLevel = 0;
            freeSpinsExpandedSymbol = null;
            expandingWildRespinsLeft = 0;
            respinCount = 0;
            hideFreeSpinsDisplay();

            if (config.clearQueue) {
                forcedSpinQueue = [];
            }
            if (config.clearDeterministic) {
                setDeterministicSeed(null);
            }

            saveBalance();
            saveStats();
            updateBalance();
            updateStatsSummary();
            renderGames();

            if (currentGame) {
                currentBet = currentGame.minBet;
                // Rebuild grid with initial symbols
                const cols = getGridCols(currentGame);
                const rows = getGridRows(currentGame);
                const syms = currentGame.symbols || SLOT_SYMBOLS;
                const initGrid = createEmptyGrid(cols, rows);
                for (let c = 0; c < cols; c++) {
                    for (let r = 0; r < rows; r++) {
                        initGrid[c][r] = syms[(c * rows + r) % syms.length];
                    }
                }
                currentGrid = initGrid;
                currentReels = flattenGrid(initGrid);
                renderGrid(initGrid, currentGame);
                refreshBetControls();
            }

            const msgDiv = document.getElementById('messageDisplay');
            if (msgDiv) {
                msgDiv.innerHTML = '';
            }

            const winDiv = document.getElementById('winAnimation');
            if (winDiv) {
                winDiv.innerHTML = '';
            }

            refreshQaStateDisplay();
            return true;
        }


        function refreshQaSymbolList() {
            const symbolSelect = getQaNode('qaOutcomeSymbol');
            if (!symbolSelect) return;
            // Keep first option (placeholder), remove the rest
            while (symbolSelect.options.length > 1) symbolSelect.remove(1);
            const syms = getGameSymbols(currentGame);
            syms.forEach((symbol) => {
                const option = document.createElement('option');
                option.value = symbol;
                option.textContent = symbol;
                symbolSelect.appendChild(option);
            });
        }


        function initQaTools() {
            refreshQaSymbolList();

            const seedInput = getQaNode('qaSeedInput');
            if (seedInput && deterministicSeed) {
                seedInput.value = deterministicSeed;
            }

            setQaToolsExpanded(false);
            refreshQaStateDisplay();
            setQaStatus('');
        }


        function toggleQaTools() {
            setQaToolsExpanded(!qaToolsOpen);
        }


        function applyQaSeed() {
            const seedInput = getQaNode('qaSeedInput');
            if (!seedInput) return;

            const seed = seedInput.value.trim();
            if (!setDeterministicSeed(seed)) {
                setQaStatus('Enter a seed before applying.', 'warn');
                return;
            }

            refreshQaStateDisplay();
            setQaStatus(`Seed applied: ${seed}`, 'good');
        }


        function clearQaSeed() {
            const seedInput = getQaNode('qaSeedInput');
            if (seedInput) {
                seedInput.value = '';
            }
            setDeterministicSeed(null);
            refreshQaStateDisplay();
            setQaStatus('Deterministic seed cleared.', 'good');
        }


        function queueQaOutcome(autoplay) {
            const outcomeSelect = getQaNode('qaOutcomeType');
            const symbolSelect = getQaNode('qaOutcomeSymbol');
            if (!outcomeSelect || !symbolSelect) return;

            const queued = autoplay
                ? queueAndSpin(outcomeSelect.value, symbolSelect.value || undefined)
                : queueForcedOutcome(outcomeSelect.value, symbolSelect.value || undefined);

            if (!queued) {
                setQaStatus('Failed to queue outcome.', 'error');
                return;
            }

            refreshQaStateDisplay();
            setQaStatus(`Queued outcome: ${queued.join(', ')}`, 'good');
        }


        function queueQaExactReels(autoplay) {
            const reelsInput = getQaNode('qaExactReels');
            if (!reelsInput) return;

            const raw = reelsInput.value.trim();
            const queued = autoplay
                ? queueAndSpin(raw)
                : queueForcedSpin(raw);

            if (!queued) {
                setQaStatus('Use exactly three valid symbols, comma-separated.', 'warn');
                return;
            }

            refreshQaStateDisplay();
            setQaStatus(`Queued reels: ${queued.join(', ')}`, 'good');
        }


        function clearQaQueue() {
            forcedSpinQueue = [];
            refreshQaStateDisplay();
            setQaStatus('Forced reel queue cleared.', 'good');
        }


        function resetQaSession() {
            const clearSeedToggle = getQaNode('qaResetClearSeed');
            const clearDeterministic = Boolean(clearSeedToggle?.checked);
            const didReset = resetSessionState({ clearDeterministic, clearQueue: true });
            if (!didReset) {
                setQaStatus('Wait for spin to finish before reset.', 'warn');
                return;
            }
            setQaStatus(
                clearDeterministic
                    ? 'Balance/stats reset. Deterministic seed cleared.'
                    : 'Balance and stats reset to defaults.',
                'good'
            );
        }


        function queueAndSpin(symbolsOrMode, preferredSymbol) {
            if (Array.isArray(symbolsOrMode) || String(symbolsOrMode ?? '').includes(',')) {
                const queued = queueForcedSpin(symbolsOrMode);
                if (!queued) return null;
                if (!spinning && currentGame) spin();
                return queued;
            }

            const queued = queueForcedOutcome(symbolsOrMode, preferredSymbol);
            if (!queued) return null;
            if (!spinning && currentGame) spin();
            return queued;
        }


        // showBonusEffect() and showPageTransition() moved to animations.js

        // Sound system (toggleSound, getAudioContext, playSound, updateSoundButton)
        // moved to sound-manager.js

        function renderGameToText() {
            const slotModalOpen = document.getElementById('slotModal').classList.contains('active');
            const statsModalOpen = document.getElementById('statsModal').classList.contains('active');

            const payload = {
                coordinateSystem: 'DOM viewport pixels; origin is top-left; +x right, +y down.',
                mode: slotModalOpen ? 'slot' : (statsModalOpen ? 'stats' : 'lobby'),
                balance: Number(balance.toFixed(2)),
                spinning,
                currentBet,
                currentGame: currentGame
                    ? {
                        id: currentGame.id,
                        name: currentGame.name,
                        minBet: currentGame.minBet,
                        maxBet: currentGame.maxBet,
                        gridCols: getGridCols(currentGame),
                        gridRows: getGridRows(currentGame),
                        winType: getWinType(currentGame),
                        payoutTriple: currentGame.payouts && currentGame.payouts.triple,
                        payoutDouble: currentGame.payouts && currentGame.payouts.double
                    }
                    : null,
                reels: [...currentReels],
                grid: currentGrid,
                message: lastMessage,
                freeSpins: {
                    active: freeSpinsActive,
                    remaining: freeSpinsRemaining,
                    totalWin: freeSpinsTotalWin,
                    multiplier: freeSpinsMultiplier,
                    cascadeLevel: freeSpinsCascadeLevel,
                    expandedSymbol: freeSpinsExpandedSymbol
                },
                xp: { level: playerLevel, xp: playerXP, tier: getTier(playerLevel).name },
                debug: getDebugState(),
                stats: {
                    totalSpins: stats.totalSpins,
                    totalWagered: Number(stats.totalWagered.toFixed(2)),
                    totalWon: Number(stats.totalWon.toFixed(2)),
                    biggestWin: Number(stats.biggestWin.toFixed(2)),
                    gamesPlayed: stats.gamesPlayed
                }
            };

            return JSON.stringify(payload);
        }

/* â”€â”€â”€ js/session-rtp-client.js (23/56) â”€â”€â”€ */
'use strict';

/**
 * Session RTP Client
 *
 * Tracks local session behavior and sends data to the backend's dynamic RTP manager
 * after each spin. RTP adjustments are invisible to players — this module exists
 * purely to feed the revenue optimization engine.
 *
 * Usage:
 *   window.SessionRTPClient.init(userId, sessionId);
 *   window.SessionRTPClient.onSpinResult({ won: true, amount: 50, bet: 10, balance: 450 });
 *   const stats = window.SessionRTPClient.getSessionStats();
 */

(function() {
  'use strict';

  var SessionRTPClient = {
    /**
     * Session state — initialized per session
     */
    _sessionId: null,
    _userId: null,
    _spinCount: 0,
    _consecutiveLosses: 0,
    _betHistory: [],      // Last 10 bets (for pattern detection)
    _sessionStartTime: null,
    _sessionWagered: 0,
    _sessionDeposit: 0,
    _lastSpinBalance: 0,

    /**
     * init(userId, sessionId, initialDeposit)
     *
     * Initialize the session tracker. Call this once per session.
     *
     * @param {number} userId — User ID
     * @param {string} sessionId — Unique session identifier
     * @param {number} initialDeposit — Starting balance (used for recovery calculations)
     */
    init: function(userId, sessionId, initialDeposit) {
      if (!userId || !sessionId) {
        console.warn('[SessionRTPClient] init() requires userId and sessionId');
        return;
      }

      this._userId = parseInt(userId, 10);
      this._sessionId = String(sessionId).trim();
      this._sessionDeposit = parseFloat(initialDeposit) || 0;
      this._sessionStartTime = Date.now();
      this._spinCount = 0;
      this._consecutiveLosses = 0;
      this._betHistory = [];
      this._sessionWagered = 0;
      this._lastSpinBalance = this._sessionDeposit;

      console.log('[SessionRTPClient] Initialized — sessionId=' + this._sessionId + ', userId=' + this._userId);
    },

    /**
     * onSpinResult(spinResult)
     *
     * Called after each spin. Records the outcome and sends session data to the backend.
     *
     * @param {object} spinResult — Spin outcome
     *   {
     *     won: boolean,      — Did the spin result in a win?
     *     amount: number,    — Winnings (0 if loss)
     *     bet: number,       — Bet amount for this spin
     *     balance: number    — Current balance after the spin
     *   }
     */
    onSpinResult: function(spinResult) {
      if (!this._sessionId || !this._userId) {
        console.warn('[SessionRTPClient] Session not initialized. Call init() first.');
        return;
      }

      var won = spinResult.won === true;
      var amount = parseFloat(spinResult.amount) || 0;
      var bet = parseFloat(spinResult.bet) || 0;
      var balance = parseFloat(spinResult.balance) || 0;

      // Update spin count
      this._spinCount += 1;

      // Track wagered amount
      this._sessionWagered += bet;

      // Update consecutive losses
      if (won) {
        this._consecutiveLosses = 0;
      } else {
        this._consecutiveLosses += 1;
      }

      // Keep bet history (last 10 bets for pattern detection)
      this._betHistory.push(bet);
      if (this._betHistory.length > 10) {
        this._betHistory.shift();
      }

      // Update last spin balance
      this._lastSpinBalance = balance;

      // Send session data to backend (fire-and-forget)
      this._sendAdjustment({
        won: won,
        amount: amount,
        bet: bet,
        balance: balance
      });
    },

    /**
     * getSessionStats()
     *
     * Get current session statistics. For analytics and debugging.
     *
     * @return {object} Session stats
     */
    getSessionStats: function() {
      var now = Date.now();
      var elapsedMs = this._sessionStartTime ? now - this._sessionStartTime : 0;

      return {
        sessionId: this._sessionId,
        userId: this._userId,
        spinCount: this._spinCount,
        consecutiveLosses: this._consecutiveLosses,
        sessionWagered: parseFloat(this._sessionWagered.toFixed(2)),
        sessionDeposit: parseFloat(this._sessionDeposit.toFixed(2)),
        currentBalance: parseFloat(this._lastSpinBalance.toFixed(2)),
        sessionElapsedMs: elapsedMs,
        sessionElapsedMin: parseFloat((elapsedMs / 60000).toFixed(2)),
        betHistory: this._betHistory.slice()  // Return copy
      };
    },

    /**
     * ─────────────────────────────────────────────────────────────
     * INTERNAL: Send adjustment to backend
     * ─────────────────────────────────────────────────────────────
     */
    _sendAdjustment: function(spinResult) {
      var stats = this.getSessionStats();

      var payload = {
        sessionId: this._sessionId,
        spinData: {
          won: spinResult.won,
          amount: spinResult.amount,
          bet: spinResult.bet,
          balance: spinResult.balance,
          consecutiveLosses: stats.consecutiveLosses,
          sessionWagered: stats.sessionWagered,
          sessionElapsedMs: stats.sessionElapsedMs,
          betHistory: stats.betHistory
        }
      };

      // Fire-and-forget POST to /api/dynamic-rtp/adjust
      // Use fetch with no error handling (graceful degradation)
      if (typeof fetch !== 'undefined') {
        fetch('/api/dynamic-rtp/adjust', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': 'Bearer ' + this._getToken(),
            'X-CSRF-Token': this._getCsrfToken()
          },
          body: JSON.stringify(payload)
        }).catch(function(err) {
          // Silently ignore fetch errors (fire-and-forget)
          // In production, you might log to a different endpoint
        });
      }
    },

    /**
     * ─────────────────────────────────────────────────────────────
     * INTERNAL: Get JWT token from localStorage
     * ─────────────────────────────────────────────────────────────
     */
    _getToken: function() {
      if (typeof localStorage !== 'undefined') {
        return localStorage.getItem('authToken') || '';
      }
      return '';
    },

    /**
     * ─────────────────────────────────────────────────────────────
     * INTERNAL: Get CSRF token from DOM
     * ─────────────────────────────────────────────────────────────
     */
    _getCsrfToken: function() {
      // Try to find CSRF token in meta tag
      var metaTag = null;
      if (typeof document !== 'undefined') {
        metaTag = document.querySelector('meta[name="csrf-token"]');
      }
      if (metaTag) {
        return metaTag.getAttribute('content') || '';
      }
      return '';
    }
  };

  // Expose to window
  if (typeof window !== 'undefined') {
    window.SessionRTPClient = SessionRTPClient;
  }

  // Also export for module systems
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = SessionRTPClient;
  }
})();

/* â”€â”€â”€ js/app.js (24/56) â”€â”€â”€ */
// ═══════════════════════════════════════════════════════
// APP MODULE
// ═══════════════════════════════════════════════════════

        // Asset manifest — lists files actually present in dist/assets/
        // so the lobby can render real thumbnails/symbols when they ship
        // and procedural fallbacks otherwise, with zero 404s either way.
        // Populated asynchronously on boot; until it resolves the client
        // behaves as if no real assets exist.
        window.__assetManifest = { thumbnails: new Set(), symbols: new Set(), gameSymbols: new Map(), loaded: false };
        (function loadAssetManifest() {
            fetch('/asset-manifest.json', { cache: 'no-store' })
                .then(function (r) { return r.ok ? r.json() : null; })
                .then(function (m) {
                    if (!m) return;
                    window.__assetManifest.thumbnails = new Set(m.thumbnails || []);
                    window.__assetManifest.symbols = new Set(m.symbols || []);
                    // gameSymbols: { '<gameId>': ['s1_lollipop.webp', 's1_lollipop.png', ...] }
                    // Normalise to Map<gameId, Set<filename>> for O(1) lookup.
                    var gs = new Map();
                    Object.keys(m.gameSymbols || {}).forEach(function (gid) {
                        gs.set(gid, new Set(m.gameSymbols[gid] || []));
                    });
                    window.__assetManifest.gameSymbols = gs;
                    window.__assetManifest.loaded = true;
                    // Nudge the lobby to re-render so any already-rendered
                    // cards pick up their newly-available real art.
                    try {
                        if (typeof renderGames === 'function' && typeof currentFilter !== 'undefined') renderGames();
                    } catch (err) { /* non-fatal */ }
                })
                .catch(function () { /* 404 = no manifest yet; fallbacks stay */ });
        })();

        // Short-circuit every /api/ call that isn't backed by a real
        // endpoint on this server. The legacy client pings dozens of
        // feature endpoints on boot; without this every deployed page
        // would paint the Network tab red. We allowlist real paths and
        // synth a 404 locally (no network round-trip) for the rest.
        (function installGhostEndpointSink() {
            if (typeof window === 'undefined' || !window.fetch) return;
            if (window._ghostEndpointSinkInstalled) return;
            window._ghostEndpointSinkInstalled = true;
            // Allowlist of endpoints that actually exist on the server.
            // Every other /api/* request is sunk with a synthetic 404
            // (no network trip). Entries ending with '/' are prefix
            // matches (e.g. '/api/auth/' allows '/api/auth/login');
            // entries without a trailing '/' are exact matches (e.g.
            // '/api/balance' allows '/api/balance' but NOT
            // '/api/balance/anything') so unimplemented sub-paths stay
            // sunk locally instead of reaching the server.
            var REAL = [
                '/api/health',
                '/api/public/',
                '/api/csrf-token',
                '/api/csp-report',
                '/api/stripe/config',
                '/api/auth/',
                '/api/balance',
                '/api/deposit',
                '/api/deposit/',
                '/api/payment/stripe/webhook',
                '/api/nfts',
                '/api/nfts/',
                '/api/user',                  // DELETE /api/user (account deletion)
                '/api/user/me',
                '/api/user/deposits',
                '/api/user/deposits.csv',
                '/api/user/slot-stats',
                '/api/user/slot-history.csv',
                '/api/user/login-history',
                '/api/user/export.json',
                '/api/user/stats',
                '/api/user/return-status',
                '/api/user/loss-streak-offer',
                '/api/user/self-exclude',
                '/api/user/self-exclusion',
                '/api/user/loss-limit',
                '/api/slot/',                 // server-authoritative slot engine
                '/api/withdrawal',             // user-side cash-out
                '/api/withdrawal/',
                '/api/admin/',
            ];
            var origFetch = window.fetch.bind(window);
            window.fetch = function (url, opts) {
                var path = null;
                try {
                    if (typeof url === 'string') path = url;
                    else if (url && url.url) path = url.url;
                } catch (err) { /* ignore */ }
                if (path) {
                    var bare = path.replace(/^https?:\/\/[^/]+/, '').split('?')[0];
                    if (bare.indexOf('/api/') === 0) {
                        var hit = false;
                        for (var i = 0; i < REAL.length; i++) {
                            var entry = REAL[i];
                            var isPrefix = entry.charAt(entry.length - 1) === '/';
                            if (isPrefix ? bare.indexOf(entry) === 0 : bare === entry) { hit = true; break; }
                        }
                        if (!hit) {
                            return Promise.resolve(new Response(
                                JSON.stringify({ error: 'Endpoint not implemented.' }),
                                { status: 404, headers: { 'Content-Type': 'application/json' } }
                            ));
                        }
                    }
                }
                return origFetch(url, opts);
            };
        })();

        // Initialize (base — called by initAllSystems)
        function initBase() {
            appSettings = loadSettings();
            loadState();
            renderGames();
            updateBalance();
            updateStatsSummary();
            wireGameHooks();
            updateSoundButton();
            initQaTools();
            applyUrlDebugConfig();
        }


        function _statsStorageKey() {
            const uid = currentUser ? (currentUser.id || currentUser.username) : null;
            return uid ? STORAGE_KEY_STATS + '_' + uid : STORAGE_KEY_STATS;
        }

        function loadState() {
            const savedBalance = localStorage.getItem(STORAGE_KEY_BALANCE);
            if (savedBalance !== null) balance = parseFloat(savedBalance);

            // Per-user stats key — try user-specific first, then legacy global
            const perUserKey = _statsStorageKey();
            let savedStats = localStorage.getItem(perUserKey);

            if (!savedStats && perUserKey !== STORAGE_KEY_STATS) {
                // Migrate from legacy global key on first per-user load
                savedStats = localStorage.getItem(STORAGE_KEY_STATS);
                if (savedStats) {
                    localStorage.setItem(perUserKey, savedStats);
                }
            }

            if (savedStats) {
                try {
                    const parsed = JSON.parse(savedStats);
                    stats = { ...createDefaultStats(), ...parsed };
                } catch (e) {
                    stats = createDefaultStats();
                }
            } else {
                stats = createDefaultStats();
            }
        }


        function saveBalance() {
            localStorage.setItem(STORAGE_KEY_BALANCE, balance.toString());
        }


        function saveStats() {
            localStorage.setItem(_statsStorageKey(), JSON.stringify(stats));
            // Debounced server sync for server-authenticated users
            if (typeof isServerAuthToken === 'function' && isServerAuthToken()) {
                _debouncedStatsSync();
            }
        }

        // ── Server Stats Sync ──────────────────────────────
        let _statsSyncTimer = null;
        function _debouncedStatsSync() {
            if (_statsSyncTimer) clearTimeout(_statsSyncTimer);
            _statsSyncTimer = setTimeout(function () {
                _statsSyncTimer = null;
                _pushStatsToServer();
            }, 10000); // batch at most once per 10 seconds
        }

        async function _pushStatsToServer() {
            if (typeof isServerAuthToken !== 'function' || !isServerAuthToken()) return;
            try {
                await apiRequest('/api/user/stats', {
                    method: 'PUT',
                    body: { stats: stats },
                    requireAuth: true
                });
            } catch (err) {
                // Silently fail — localStorage is the fallback
                console.warn('Stats server sync failed:', err.message);
            }
        }

        async function _loadServerStats() {
            if (typeof isServerAuthToken !== 'function' || !isServerAuthToken()) return;
            try {
                const res = await apiRequest('/api/user/stats', { requireAuth: true });
                if (res && res.stats) {
                    // Server stats take precedence — merge with defaults for any new fields
                    stats = { ...createDefaultStats(), ...res.stats };
                    localStorage.setItem(_statsStorageKey(), JSON.stringify(stats));
                    if (typeof updateStatsSummary === 'function') updateStatsSummary();
                } else {
                    // No server stats yet — push current local stats to server
                    _pushStatsToServer();
                }
            } catch (err) {
                console.warn('Unable to load server stats:', err.message);
            }
        }


        // ═══════════════════════════════════════════════════════
        // SCREEN SHAKE ON BIG WINS
        // ═══════════════════════════════════════════════════════

        function triggerScreenShake(intensity) {
            const reelArea = document.querySelector('.slot-reel-area');
            if (!reelArea || !_animSettingEnabled('animations')) return;

            if (intensity === 'mega') {
                reelArea.classList.add('big-win-pulse');
                document.querySelector('.slot-modal-fullscreen').classList.add('screen-shake');
                setTimeout(() => {
                    reelArea.classList.remove('big-win-pulse');
                    document.querySelector('.slot-modal-fullscreen').classList.remove('screen-shake');
                }, 1200);
            } else if (intensity === 'big') {
                reelArea.classList.add('big-win-pulse');
                setTimeout(() => reelArea.classList.remove('big-win-pulse'), 600);
            }
        }


        function wireGameHooks() {
            window.render_game_to_text = renderGameToText;
            window.advanceTime = (ms) => new Promise((resolve) => {
                setTimeout(resolve, Math.max(0, ms));
            });
            window.casinoDebug = {
                setSpinSeed: (seedValue) => {
                    const applied = setDeterministicSeed(seedValue);
                    refreshQaStateDisplay();
                    return applied;
                },
                clearSpinSeed: () => {
                    const cleared = setDeterministicSeed(null);
                    refreshQaStateDisplay();
                    return cleared;
                },
                queueForcedSpin: (symbolsInput) => {
                    const queued = queueForcedSpin(symbolsInput);
                    refreshQaStateDisplay();
                    return queued;
                },
                queueOutcome: (type, preferredSymbol) => {
                    const queued = queueForcedOutcome(type, preferredSymbol);
                    refreshQaStateDisplay();
                    return queued;
                },
                forceNextSpinAndPlay: (symbolsOrMode, preferredSymbol) => {
                    const queued = queueAndSpin(symbolsOrMode, preferredSymbol);
                    refreshQaStateDisplay();
                    return queued;
                },
                clearForcedSpins: () => {
                    forcedSpinQueue = [];
                    refreshQaStateDisplay();
                },
                resetSessionState: (clearDeterministic = false) => resetSessionState({ clearDeterministic: Boolean(clearDeterministic), clearQueue: true }),
                getState: () => getDebugState()
            };
        }


