                    '.levelup-bonus-title{font-size:1.6rem;font-weight:800;color:#ffd700;margin-bottom:8px}',
                    '.levelup-bonus-level{font-size:1.15rem;color:#e0e0ff;margin-bottom:6px;font-weight:600}',
