// ═══════════════════════════════════════════════════════════════════════════
// Sound Settings UI Module — Casino Dark Theme with Gold Accents
// ═══════════════════════════════════════════════════════════════════════════
// Exposes: window.SoundSettings = { init(), show() }
// localStorage key: 'matrixSpins_soundPrefs'
// ═══════════════════════════════════════════════════════════════════════════

(function () {
    'use strict';

    // ── Default Preferences ──────────────────────────────────────────────
    var DEFAULT_PREFS = {
        masterVolume: 100,
        music: true,
        sfx: true,
        ambience: true,
        uiClicks: true,
        muteAll: false
    };

    var prefs = {};
    var modalElement = null;

    // ── Initialize Preferences from localStorage ──────────────────────
    function init() {
        try {
            var stored = localStorage.getItem('matrixSpins_soundPrefs');
            if (stored) {
                prefs = Object.assign({}, DEFAULT_PREFS, JSON.parse(stored));
            } else {
                prefs = Object.assign({}, DEFAULT_PREFS);
            }
        } catch (e) {
            console.warn('SoundSettings: Failed to parse stored prefs, using defaults:', e);
            prefs = Object.assign({}, DEFAULT_PREFS);
        }

        applyPreferences();
    }

    // ── Apply Preferences to Existing Sound System ───────────────────
    function applyPreferences() {
        // Set master volume in SoundManager if available
        if (typeof setSoundVolume === 'function') {
            var volumeRatio = prefs.masterVolume / 100;
            setSoundVolume(volumeRatio);
        } else if (window.SoundManager && typeof window.SoundManager.setSoundVolume === 'function') {
            var volumeRatio = prefs.masterVolume / 100;
            window.SoundManager.setSoundVolume(volumeRatio);
        }

        // Apply mute all
        if (prefs.muteAll) {
            if (typeof toggleSound === 'function') {
                toggleSound(false);
            } else if (window.SoundManager && typeof window.SoundManager.setSoundEnabled === 'function') {
                window.SoundManager.setSoundEnabled(false);
            }
        }

        // Store updated prefs
        savePref();
    }

    // ── Save Preferences to localStorage ─────────────────────────────
    function savePref() {
        try {
            localStorage.setItem('matrixSpins_soundPrefs', JSON.stringify(prefs));
        } catch (e) {
            console.warn('SoundSettings: Failed to save preferences:', e);
        }
    }

    // ── Play Preview Sound ───────────────────────────────────────────
    function playPreview() {
        if (!prefs.muteAll && typeof playSound === 'function') {
            playSound('spin');
        }
    }

    // ── Create Modal DOM ─────────────────────────────────────────────
    function createModal() {
        var container = document.createElement('div');
        container.id = 'sound-settings-overlay';
        container.innerHTML = '\
            <div class="sound-settings-modal">\
                <div class="sound-settings-header">\
                    <h2>Sound Settings</h2>\
                    <button class="sound-settings-close" aria-label="Close">&times;</button>\
                </div>\
                <div class="sound-settings-content">\
                    <!-- Master Volume -->\
                    <div class="sound-settings-group">\
                        <label for="master-volume">Master Volume</label>\
                        <div class="sound-settings-slider-container">\
                            <input type="range" id="master-volume" class="sound-settings-slider" min="0" max="100" />\
                            <span class="sound-settings-value">100%</span>\
                        </div>\
                    </div>\
                    \
                    <!-- Mute All Toggle -->\
                    <div class="sound-settings-group">\
                        <label class="sound-settings-toggle">\
                            <input type="checkbox" id="mute-all" />\
                            <span>Mute All</span>\
                        </label>\
                    </div>\
                    \
                    <!-- Category Toggles -->\
                    <div class="sound-settings-divider">Sound Categories</div>\
                    \
                    <div class="sound-settings-group">\
                        <label class="sound-settings-toggle">\
                            <input type="checkbox" id="toggle-music" />\
                            <span>Music</span>\
                        </label>\
                    </div>\
                    \
                    <div class="sound-settings-group">\
                        <label class="sound-settings-toggle">\
                            <input type="checkbox" id="toggle-sfx" />\
                            <span>SFX (Spins, Wins)</span>\
                        </label>\
                    </div>\
                    \
                    <div class="sound-settings-group">\
                        <label class="sound-settings-toggle">\
                            <input type="checkbox" id="toggle-ambience" />\
                            <span>Ambience</span>\
                        </label>\
                    </div>\
                    \
                    <div class="sound-settings-group">\
                        <label class="sound-settings-toggle">\
                            <input type="checkbox" id="toggle-ui-clicks" />\
                            <span>UI Clicks</span>\
                        </label>\
                    </div>\
                    \
                    <!-- Preview Button -->\
                    <div class="sound-settings-preview">\
                        <button id="sound-preview-btn" class="sound-settings-button">Play Preview</button>\
                    </div>\
                </div>\
            </div>\
        ';

        return container;
    }

    // ── Inject Styles ────────────────────────────────────────────────
    function injectStyles() {
        if (document.getElementById('sound-settings-styles')) {
            return; // Already injected
        }

        var style = document.createElement('style');
        style.id = 'sound-settings-styles';
        style.textContent = `
            #sound-settings-overlay {
                position: fixed;
                top: 0;
                left: 0;
                width: 100%;
                height: 100%;
                background: rgba(0, 0, 0, 0.7);
                display: flex;
                align-items: center;
                justify-content: center;
                z-index: 10000;
                animation: fadeIn 0.3s ease-out;
            }

            @keyframes fadeIn {
                from { opacity: 0; }
                to { opacity: 1; }
            }

            .sound-settings-modal {
                background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
                border: 2px solid #fbbf24;
                border-radius: 12px;
                box-shadow: 0 20px 60px rgba(0, 0, 0, 0.8), inset 0 1px 0 rgba(251, 191, 36, 0.2);
                max-width: 400px;
                width: 90%;
                max-height: 80vh;
                overflow-y: auto;
                padding: 0;
                font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
            }

            .sound-settings-header {
                display: flex;
                justify-content: space-between;
                align-items: center;
                padding: 20px;
                border-bottom: 1px solid rgba(251, 191, 36, 0.3);
                background: linear-gradient(135deg, rgba(26, 26, 46, 0.9) 0%, rgba(22, 33, 62, 0.9) 100%);
            }

            .sound-settings-header h2 {
                margin: 0;
                color: #fbbf24;
                font-size: 24px;
                font-weight: 600;
                letter-spacing: 0.5px;
            }

            .sound-settings-close {
                background: none;
                border: none;
                color: #fbbf24;
                font-size: 32px;
                cursor: pointer;
                padding: 0;
                width: 40px;
                height: 40px;
                display: flex;
                align-items: center;
                justify-content: center;
                border-radius: 6px;
                transition: all 0.2s ease;
                line-height: 1;
            }

            .sound-settings-close:hover {
                background: rgba(251, 191, 36, 0.1);
                color: #fcd34d;
            }

            .sound-settings-content {
                padding: 20px;
            }

            .sound-settings-group {
                margin-bottom: 18px;
            }

            .sound-settings-group > label:first-child:not(.sound-settings-toggle) {
                display: block;
                color: #e0e0e0;
                font-size: 14px;
                font-weight: 500;
                margin-bottom: 8px;
                letter-spacing: 0.3px;
            }

            .sound-settings-slider-container {
                display: flex;
                align-items: center;
                gap: 12px;
            }

            .sound-settings-slider {
                flex: 1;
                height: 6px;
                -webkit-appearance: none;
                appearance: none;
                background: linear-gradient(to right, rgba(251, 191, 36, 0.2), rgba(251, 191, 36, 0.3));
                border-radius: 3px;
                outline: none;
                cursor: pointer;
            }

            .sound-settings-slider::-webkit-slider-thumb {
                -webkit-appearance: none;
                appearance: none;
                width: 18px;
                height: 18px;
                border-radius: 50%;
                background: linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%);
                cursor: pointer;
                box-shadow: 0 2px 8px rgba(251, 191, 36, 0.4), inset 0 1px 2px rgba(255, 255, 255, 0.3);
                border: 2px solid #fbbf24;
                transition: all 0.2s ease;
            }

            .sound-settings-slider::-webkit-slider-thumb:hover {
                box-shadow: 0 4px 12px rgba(251, 191, 36, 0.6), inset 0 1px 2px rgba(255, 255, 255, 0.3);
                transform: scale(1.1);
            }

            .sound-settings-slider::-moz-range-thumb {
                width: 18px;
                height: 18px;
                border-radius: 50%;
                background: linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%);
                cursor: pointer;
                box-shadow: 0 2px 8px rgba(251, 191, 36, 0.4), inset 0 1px 2px rgba(255, 255, 255, 0.3);
                border: 2px solid #fbbf24;
                transition: all 0.2s ease;
            }

            .sound-settings-slider::-moz-range-thumb:hover {
                box-shadow: 0 4px 12px rgba(251, 191, 36, 0.6), inset 0 1px 2px rgba(255, 255, 255, 0.3);
                transform: scale(1.1);
            }

            .sound-settings-value {
                color: #fbbf24;
                font-weight: 600;
                font-size: 14px;
                min-width: 45px;
                text-align: right;
                letter-spacing: 0.3px;
            }

            .sound-settings-toggle {
                display: flex;
                align-items: center;
                cursor: pointer;
                user-select: none;
                gap: 10px;
            }

            .sound-settings-toggle input[type="checkbox"] {
                width: 20px;
                height: 20px;
                cursor: pointer;
                accent-color: #fbbf24;
                transition: all 0.2s ease;
            }

            .sound-settings-toggle input[type="checkbox"]:hover {
                transform: scale(1.1);
            }

            .sound-settings-toggle span {
                color: #e0e0e0;
                font-size: 14px;
                font-weight: 500;
            }

            .sound-settings-divider {
                color: #fbbf24;
                font-size: 12px;
                font-weight: 600;
                text-transform: uppercase;
                letter-spacing: 1px;
                margin: 24px 0 16px 0;
                padding-top: 16px;
                border-top: 1px solid rgba(251, 191, 36, 0.2);
            }

            .sound-settings-preview {
                margin-top: 24px;
                padding-top: 16px;
                border-top: 1px solid rgba(251, 191, 36, 0.2);
                text-align: center;
            }

            .sound-settings-button {
                background: linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%);
                color: #1a1a2e;
                border: none;
                border-radius: 8px;
                padding: 12px 24px;
                font-size: 14px;
                font-weight: 600;
                cursor: pointer;
                transition: all 0.3s ease;
                box-shadow: 0 4px 15px rgba(251, 191, 36, 0.3);
                letter-spacing: 0.5px;
                text-transform: uppercase;
            }

            .sound-settings-button:hover {
                background: linear-gradient(135deg, #fcd34d 0%, #fbbf24 100%);
                box-shadow: 0 6px 20px rgba(251, 191, 36, 0.5);
                transform: translateY(-2px);
            }

            .sound-settings-button:active {
                transform: translateY(0);
                box-shadow: 0 2px 10px rgba(251, 191, 36, 0.3);
            }

            @media (max-width: 480px) {
                .sound-settings-modal {
                    width: 95%;
                    max-height: 85vh;
                }

                .sound-settings-header h2 {
                    font-size: 20px;
                }

                .sound-settings-content {
                    padding: 16px;
                }
            }
        `;

        document.head.appendChild(style);
    }

    // ── Update Modal UI from Preferences ────────────────────────────
    function updateModalUI() {
        if (!modalElement) return;

        var masterVolumeInput = modalElement.querySelector('#master-volume');
        var masterVolumeValue = modalElement.querySelector('.sound-settings-value');
        var muteAllCheckbox = modalElement.querySelector('#mute-all');
        var musicCheckbox = modalElement.querySelector('#toggle-music');
        var sfxCheckbox = modalElement.querySelector('#toggle-sfx');
        var ambienceCheckbox = modalElement.querySelector('#toggle-ambience');
        var uiClicksCheckbox = modalElement.querySelector('#toggle-ui-clicks');

        if (masterVolumeInput) {
            masterVolumeInput.value = prefs.masterVolume;
            masterVolumeValue.textContent = prefs.masterVolume + '%';
        }
        if (muteAllCheckbox) muteAllCheckbox.checked = prefs.muteAll;
        if (musicCheckbox) musicCheckbox.checked = prefs.music;
        if (sfxCheckbox) sfxCheckbox.checked = prefs.sfx;
        if (ambienceCheckbox) ambienceCheckbox.checked = prefs.ambience;
        if (uiClicksCheckbox) uiClicksCheckbox.checked = prefs.uiClicks;
    }

    // ── Attach Event Handlers ────────────────────────────────────────
    function attachEventHandlers() {
        if (!modalElement) return;

        var overlay = modalElement;
        var closeBtn = modalElement.querySelector('.sound-settings-close');
        var masterVolumeInput = modalElement.querySelector('#master-volume');
        var masterVolumeValue = modalElement.querySelector('.sound-settings-value');
        var muteAllCheckbox = modalElement.querySelector('#mute-all');
        var musicCheckbox = modalElement.querySelector('#toggle-music');
        var sfxCheckbox = modalElement.querySelector('#toggle-sfx');
        var ambienceCheckbox = modalElement.querySelector('#toggle-ambience');
        var uiClicksCheckbox = modalElement.querySelector('#toggle-ui-clicks');
        var previewBtn = modalElement.querySelector('#sound-preview-btn');

        // Close modal
        closeBtn.addEventListener('click', hideModal);
        overlay.addEventListener('click', function (e) {
            if (e.target === overlay) {
                hideModal();
            }
        });

        // Master volume slider
        masterVolumeInput.addEventListener('input', function () {
            prefs.masterVolume = parseInt(this.value, 10);
            masterVolumeValue.textContent = prefs.masterVolume + '%';
            applyPreferences();
        });

        // Mute all toggle
        muteAllCheckbox.addEventListener('change', function () {
            prefs.muteAll = this.checked;
            if (typeof toggleSound === 'function') {
                toggleSound(!this.checked);
            } else if (window.SoundManager && typeof window.SoundManager.setSoundEnabled === 'function') {
                window.SoundManager.setSoundEnabled(!this.checked);
            }
            savePref();
        });

        // Category toggles
        musicCheckbox.addEventListener('change', function () {
            prefs.music = this.checked;
            savePref();
        });

        sfxCheckbox.addEventListener('change', function () {
            prefs.sfx = this.checked;
            savePref();
        });

        ambienceCheckbox.addEventListener('change', function () {
            prefs.ambience = this.checked;
            savePref();
        });

        uiClicksCheckbox.addEventListener('change', function () {
            prefs.uiClicks = this.checked;
            savePref();
        });

        // Preview button
        previewBtn.addEventListener('click', playPreview);
    }

    // ── Show Modal ───────────────────────────────────────────────────
    function show() {
        if (modalElement && modalElement.parentNode) {
            return; // Already shown
        }

        injectStyles();
        modalElement = createModal();
        updateModalUI();
        attachEventHandlers();
        document.body.appendChild(modalElement);
    }

    // ── Hide Modal ───────────────────────────────────────────────────
    function hideModal() {
        if (modalElement && modalElement.parentNode) {
            modalElement.parentNode.removeChild(modalElement);
            modalElement = null;
        }
    }

    // ── Expose API ───────────────────────────────────────────────────
    window.SoundSettings = {
        init: init,
        show: show,
        hidModal: hideModal,
        getPrefs: function () { return Object.assign({}, prefs); },
        setPrefs: function (newPrefs) {
            prefs = Object.assign(prefs, newPrefs);
            applyPreferences();
        }
    };

})();

/* â”€â”€â”€ js/keyboard-shortcuts.js (45/56) â”€â”€â”€ */
/**
 * Keyboard Shortcuts Module
 * Provides keyboard shortcuts for the Royal Slots Casino game
 */

(function() {
  'use strict';

  const KeyboardShortcuts = {
    initialized: false,
    helpOverlayId: 'keyboard-shortcuts-help',

    /**
     * Keyboard shortcut definitions
     */
    shortcuts: [
      { key: 'Space', action: 'Spin', description: 'Trigger the spin button' },
      { key: 'S', action: 'Toggle Sound', description: 'Toggle sound on/off' },
      { key: 'H', action: 'Show Help', description: 'Show shortcut help overlay' },
      { key: 'Escape', action: 'Close Modal', description: 'Close any open modal' },
      { key: 'M', action: 'Toggle Mute', description: 'Toggle mute' },
      { key: 'F', action: 'Toggle Fullscreen', description: 'Toggle fullscreen mode' },
      { key: 'L', action: 'Open Lobby', description: 'Open lobby/game list' },
      { key: 'B', action: 'Bankroll Calc', description: 'Open bankroll calculator' },
      { key: '?', action: 'Show Help', description: 'Show shortcut help overlay' }
    ],

    /**
     * Initialize keyboard shortcuts
     */
    init: function() {
      if (this.initialized) {
        console.warn('KeyboardShortcuts already initialized');
        return;
      }

      document.addEventListener('keydown', (e) => this._handleKeyDown(e));
      this.initialized = true;
      console.warn('KeyboardShortcuts initialized');
    },

    /**
     * Handle keydown events
     */
    _handleKeyDown: function(e) {
      // Don't trigger if focus is on input or textarea
      const activeElement = document.activeElement;
      if (activeElement && (activeElement.tagName === 'INPUT' || activeElement.tagName === 'TEXTAREA')) {
        return;
      }

      const key = e.key;
      const shiftKey = e.shiftKey;

      // Handle ? (Shift + /)
      if (key === '?' || (shiftKey && key === '/')) {
        e.preventDefault();
        this.showHelp();
        return;
      }

      // Handle Space
      if (key === ' ') {
        e.preventDefault();
        this._triggerSpin();
        return;
      }

      // Handle S (toggle sound)
      if (key.toLowerCase() === 's') {
        e.preventDefault();
        this._toggleSound();
        return;
      }

      // Handle H (show help)
      if (key.toLowerCase() === 'h') {
        e.preventDefault();
        this.showHelp();
        return;
      }

      // Handle Escape (close modal)
      if (key === 'Escape') {
        e.preventDefault();
        this._closeModal();
        return;
      }

      // Handle M (toggle mute)
      if (key.toLowerCase() === 'm') {
        e.preventDefault();
        this._toggleMute();
        return;
      }

      // Handle F (toggle fullscreen)
      if (key.toLowerCase() === 'f') {
        e.preventDefault();
        this._toggleFullscreen();
        return;
      }

      // Handle L (open lobby)
      if (key.toLowerCase() === 'l') {
        e.preventDefault();
        this._openLobby();
        return;
      }

      // Handle B (open bankroll calculator)
      if (key.toLowerCase() === 'b') {
        e.preventDefault();
        this._openBankrollCalculator();
        return;
      }
    },

    /**
     * Trigger spin action
     */
    _triggerSpin: function() {
      // Check if a modal is open
      if (this._isModalOpen()) {
        console.warn('Modal is open, ignoring spin command');
        return;
      }

      const spinButton = document.querySelector('[data-action="spin"], .spin-button, #spin-btn, button:contains("Spin")');
      if (spinButton) {
        spinButton.click();
        console.warn('Spin triggered via keyboard shortcut');
      } else {
        console.warn('Spin button not found');
      }
    },

    /**
     * Toggle sound
     */
    _toggleSound: function() {
      if (window.SoundSettings && typeof window.SoundSettings.toggleSound === 'function') {
        window.SoundSettings.toggleSound();
        console.warn('Sound toggled via keyboard shortcut');
      } else if (window.toggleSound && typeof window.toggleSound === 'function') {
        window.toggleSound();
        console.warn('Sound toggled via keyboard shortcut');
      } else {
        console.warn('Sound toggle function not found');
      }
    },

    /**
     * Toggle mute
     */
    _toggleMute: function() {
      if (window.SoundSettings && typeof window.SoundSettings.toggleMute === 'function') {
        window.SoundSettings.toggleMute();
        console.warn('Mute toggled via keyboard shortcut');
      } else if (window.toggleMute && typeof window.toggleMute === 'function') {
        window.toggleMute();
        console.warn('Mute toggled via keyboard shortcut');
      } else {
        console.warn('Mute toggle function not found');
      }
    },

    /**
     * Toggle fullscreen
     */
    _toggleFullscreen: function() {
      const elem = document.documentElement;
      if (!document.fullscreenElement) {
        elem.requestFullscreen().catch(err => {
          console.warn('Fullscreen request failed:', err.message);
        });
      } else {
        document.exitFullscreen().catch(err => {
          console.warn('Exit fullscreen failed:', err.message);
        });
      }
      console.warn('Fullscreen toggled via keyboard shortcut');
    },

    /**
     * Open lobby/game list
     */
    _openLobby: function() {
      if (this._isModalOpen()) {
        console.warn('Modal is open, ignoring lobby command');
        return;
      }

      if (window.GameLobby && typeof window.GameLobby.open === 'function') {
        window.GameLobby.open();
        console.warn('Lobby opened via keyboard shortcut');
      } else {
        console.warn('Game lobby not available');
      }
    },

    /**
     * Open bankroll calculator
     */
    _openBankrollCalculator: function() {
      if (this._isModalOpen()) {
        console.warn('Modal is open, ignoring bankroll calculator command');
        return;
      }

      if (window.BankrollCalculator && typeof window.BankrollCalculator.open === 'function') {
        window.BankrollCalculator.open();
        console.warn('Bankroll calculator opened via keyboard shortcut');
      } else {
        console.warn('Bankroll calculator not available');
      }
    },

    /**
     * Close modal
     */
    _closeModal: function() {
      // Close help overlay if open
      const helpOverlay = document.getElementById(this.helpOverlayId);
      if (helpOverlay) {
        this._removeHelpOverlay();
        return;
      }

      // Try common modal close methods
      if (window.Bootstrap && window.Bootstrap.Modal) {
        const modals = document.querySelectorAll('.modal.show');
        modals.forEach(modal => {
          const bsModal = window.bootstrap.Modal.getInstance(modal);
          if (bsModal) {
            bsModal.hide();
          }
        });
      }

      // Try jQuery modal
      if (window.jQuery) {
        window.jQuery('.modal.show').modal('hide');
      }

      // Try closing any open dialog
      const dialogs = document.querySelectorAll('[role="dialog"][open], .modal.show, .dialog.open');
      dialogs.forEach(dialog => {
        if (dialog.close) {
          dialog.close();
        } else {
          dialog.classList.remove('show', 'open');
          if (dialog.style.display) {
            dialog.style.display = 'none';
          }
        }
      });

      console.warn('Close modal triggered via keyboard shortcut');
    },

    /**
     * Check if a modal is open
     */
    _isModalOpen: function() {
      // Check for help overlay
      if (document.getElementById(this.helpOverlayId)) {
        return true;
      }

      // Check for Bootstrap modals
      if (document.querySelector('.modal.show')) {
        return true;
      }

      // Check for dialog elements
      if (document.querySelector('[role="dialog"][open]')) {
        return true;
      }

      // Check for generic modal classes
      if (document.querySelector('.modal.open, .dialog.open')) {
        return true;
      }

      return false;
    },

    /**
     * Show help overlay with keyboard shortcuts
     */
    showHelp: function() {
      // Remove existing overlay if present
      this._removeHelpOverlay();

      // Create overlay container
      const overlay = document.createElement('div');
      overlay.id = this.helpOverlayId;
      overlay.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: rgba(0, 0, 0, 0.7);
        display: flex;
        justify-content: center;
        align-items: center;
        z-index: 10000;
        animation: fadeIn 0.3s ease-in;
      `;

      // Create card
      const card = document.createElement('div');
      card.style.cssText = `
        background-color: #fff;
        border-radius: 12px;
        padding: 30px;
        max-width: 600px;
        max-height: 80vh;
        overflow-y: auto;
        box-shadow: 0 10px 40px rgba(0, 0, 0, 0.3);
        animation: slideUp 0.3s ease-out;
      `;

      // Add title
      const title = document.createElement('h2');
      title.textContent = 'Keyboard Shortcuts';
      title.style.cssText = `
        margin-top: 0;
        margin-bottom: 20px;
        font-size: 24px;
        color: #333;
        font-weight: 600;
      `;
      card.appendChild(title);

      // Create grid container
      const grid = document.createElement('div');
      grid.style.cssText = `
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 20px;
        margin-bottom: 20px;
      `;

      // Add shortcuts to grid
      this.shortcuts.forEach(shortcut => {
        const item = document.createElement('div');
        item.style.cssText = `
          padding: 12px;
          background-color: #f5f5f5;
          border-radius: 6px;
          border-left: 4px solid #007bff;
        `;

        const keyElement = document.createElement('div');
        keyElement.style.cssText = `
          font-weight: 600;
          color: #007bff;
          font-size: 14px;
          margin-bottom: 4px;
          font-family: monospace;
        `;
        keyElement.textContent = shortcut.key;

        const actionElement = document.createElement('div');
        actionElement.style.cssText = `
          color: #666;
          font-size: 13px;
          line-height: 1.4;
        `;
        actionElement.textContent = shortcut.description;

        item.appendChild(keyElement);
        item.appendChild(actionElement);
        grid.appendChild(item);
      });

      card.appendChild(grid);

      // Add close instruction
      const closeInfo = document.createElement('div');
      closeInfo.style.cssText = `
        text-align: center;
        color: #999;
        font-size: 12px;
        margin-top: 20px;
        padding-top: 20px;
        border-top: 1px solid #eee;
      `;
      closeInfo.textContent = 'Press ESC or click outside to close';
      card.appendChild(closeInfo);

      overlay.appendChild(card);
      document.body.appendChild(overlay);

      // Add CSS animations
      const style = document.createElement('style');
      style.textContent = `
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes slideUp {
          from {
            opacity: 0;
            transform: translateY(20px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `;
      if (!document.querySelector('style[data-keyboard-shortcuts]')) {
        style.setAttribute('data-keyboard-shortcuts', 'true');
        document.head.appendChild(style);
      }

      // Close on ESC key
      const closeHandler = (e) => {
        if (e.key === 'Escape') {
          this._removeHelpOverlay();
          document.removeEventListener('keydown', closeHandler);
        }
      };
      document.addEventListener('keydown', closeHandler);

      // Close on background click
      overlay.addEventListener('click', (e) => {
        if (e.target === overlay) {
          this._removeHelpOverlay();
        }
      });

      console.warn('Keyboard shortcuts help displayed');
    },

    /**
     * Remove help overlay
     */
    _removeHelpOverlay: function() {
      const overlay = document.getElementById(this.helpOverlayId);
      if (overlay) {
        overlay.remove();
      }
    }
  };

  // Expose to window
  window.KeyboardShortcuts = {
    init: () => KeyboardShortcuts.init(),
    showHelp: () => KeyboardShortcuts.showHelp()
  };

  console.warn('KeyboardShortcuts module loaded');
})();

/* â”€â”€â”€ js/csrf-helper.js (46/56) â”€â”€â”€ */
/**
 * CSRF Token Helper
 * Manages CSRF tokens and automatically injects them into fetch requests
 */
(function() {
    'use strict';

    let csrfToken = null;
    let lastTokenFetchTime = null;
    const TOKEN_REFRESH_INTERVAL = 30 * 60 * 1000; // 30 minutes

    // Store original fetch for wrapping
    const originalFetch = window.fetch;

    /**
     * Build the fetch init for /api/csrf-token. The server binds the
     * issued token to the current authenticated user (or 'anon'); it
     * identifies the user via the Authorization header, so we MUST
     * forward the bearer token here — otherwise we'd cache an
     * anon-bound token and every authed mutation would 403.
     */
    function csrfFetchInit() {
        const headers = {};
        try {
            const tok = localStorage.getItem('casinoToken');
            if (tok) headers['Authorization'] = 'Bearer ' + tok;
        } catch (e) { /* storage unavailable — fall through */ }
        return { headers: headers, credentials: 'same-origin' };
    }

    /**
     * Initialize CSRF protection (call after login)
     */
    async function init() {
        try {
            const response = await originalFetch('/api/csrf-token', csrfFetchInit());
            if (!response.ok) {
                console.warn('[CSRF] Failed to fetch initial token:', response.status);
                return;
            }

            const data = await response.json();
            csrfToken = data.csrfToken;
            lastTokenFetchTime = Date.now();

            console.warn('[CSRF] Token initialized');
        } catch (err) {
            console.warn('[CSRF] Failed to initialize token:', err.message);
        }
    }

    /**
     * Get current token (fetch new one if expired)
     */
    async function getToken() {
        // If no token or refresh interval exceeded, fetch new one
        if (
            !csrfToken ||
            !lastTokenFetchTime ||
            Date.now() - lastTokenFetchTime > TOKEN_REFRESH_INTERVAL
        ) {
            try {
                const response = await originalFetch('/api/csrf-token', csrfFetchInit());
                if (!response.ok) {
                    console.warn('[CSRF] Failed to refresh token:', response.status);
                    return csrfToken; // Return stale token as fallback
                }

                const data = await response.json();
                csrfToken = data.csrfToken;
                lastTokenFetchTime = Date.now();
            } catch (err) {
                console.warn('[CSRF] Failed to refresh token:', err.message);
                // Return stale token as fallback
            }
        }

        return csrfToken;
    }

    /**
     * Wrap window.fetch to add CSRF token to mutation requests.
     * Lazy-fetches a token when one isn't cached yet (pre-login flows
     * like /register and /login need a CSRF token bound to the 'anon'
     * user, and waiting for an explicit init() call was dropping those).
     */
    window.fetch = function(url, options) {
        options = options || {};
        const method = (options.method || 'GET').toUpperCase();
        const isMutation = ['POST', 'PUT', 'DELETE', 'PATCH'].includes(method);
        const isApi = typeof url === 'string' && url.indexOf('/api/') !== -1 && url.indexOf('/api/csrf-token') === -1;

        if (!isMutation || !isApi) {
            return originalFetch.apply(this, [url, options]);
        }

        // Ensure we have a fresh token, then attach it.
        return getToken().then(function (tok) {
            options.headers = Object.assign({}, options.headers || {});
            if (tok) options.headers['X-CSRF-Token'] = tok;
            return originalFetch.call(window, url, options);
        });
    };

    function invalidate() {
        csrfToken = null;
        lastTokenFetchTime = null;
    }

    // Expose public API
    window.CsrfHelper = {
        init,
        getToken,
        invalidate,
    };

    console.warn('[CSRF] Helper loaded');
})();

/* â”€â”€â”€ js/reality-check.js (47/56) â”€â”€â”€ */
﻿// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
// REALITY CHECK TIMER - Responsible Gambling Feature
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
// Periodic modal reminder (configurable interval) showing session summary.
// Pauses gameplay and prompts informed decision-making about continued play.
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

window.RealityCheck = (function() {
    'use strict';

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // CONFIGURATION & STATE
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    const STORAGE_KEY_INTERVAL = 'realityCheckInterval';
    const STORAGE_KEY_SESSION = 'realityCheckSession';
    const DEFAULT_INTERVAL_MINUTES = 30;

    let initialized = false;
    let timerHandle = null;
    let sessionData = {
        startTime: null,
        startBalance: null,
        spins: 0,
        totalWagered: 0,
        totalWon: 0,
        pausedAutoSpin: false
    };

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // INITIALIZATION
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    function init() {
        if (initialized) return;
        initialized = true;

        // Capture session start state
        sessionData.startTime = Date.now();
        sessionData.startBalance = typeof balance !== 'undefined' ? balance : 0;

        console.warn('[RealityCheck] Initialized â€” session start balance: $' + sessionData.startBalance.toFixed(2));

        // Listen for spin completion events
        window.addEventListener('spin:complete', _onSpinComplete);

        // Load saved interval preference
        const savedInterval = localStorage.getItem(STORAGE_KEY_INTERVAL);
        if (savedInterval) {
            const minutes = parseInt(savedInterval, 10);
            _startTimer(minutes);
        } else {
            _startTimer(DEFAULT_INTERVAL_MINUTES);
        }
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // SPIN TRACKING
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    function _onSpinComplete(evt) {
        sessionData.spins += 1;
        const detail = evt.detail || {};
        const betAmount = detail.betAmount || 0;
        const winAmount = detail.winAmount || 0;

        sessionData.totalWagered += betAmount;
        sessionData.totalWon += winAmount;

        console.warn('[RealityCheck] Spin tracked â€” Wager: $' + betAmount.toFixed(2) +
            ', Win: $' + winAmount.toFixed(2) +
            ', Total wager: $' + sessionData.totalWagered.toFixed(2));
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // TIMER MANAGEMENT
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    function _startTimer(minutes) {
        // Clear any existing timer
        if (timerHandle) clearTimeout(timerHandle);

        const ms = minutes * 60 * 1000;
        console.warn('[RealityCheck] Timer started for ' + minutes + ' minutes');

        timerHandle = setTimeout(function() {
            timerHandle = null;
            _pauseGameAndShowModal();
        }, ms);
    }

    function setInterval(minutes) {
        if (!initialized) {
            console.warn('[RealityCheck] Not initialized. Call init() first.');
            return;
        }

        // Validate input
        if (typeof minutes !== 'number' || minutes < 5) {
            console.warn('[RealityCheck] Invalid interval: ' + minutes + '. Using default.');
            minutes = DEFAULT_INTERVAL_MINUTES;
        }

        // Save preference
        localStorage.setItem(STORAGE_KEY_INTERVAL, minutes.toString());
        console.warn('[RealityCheck] Interval updated to ' + minutes + ' minutes');

        // Restart timer with new interval
        _startTimer(minutes);
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // GAME PAUSE & MODAL DISPLAY
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    function _pauseGameAndShowModal() {
        // Stop auto-spin if active
        if (typeof autoSpinActive !== 'undefined' && autoSpinActive) {
            sessionData.pausedAutoSpin = true;
            autoSpinActive = false;
            console.warn('[RealityCheck] Auto-spin paused for reality check');
        }

        // Pause spinning (prevent new spins)
        if (typeof spinning !== 'undefined') {
            window.spinPausedForRealityCheck = true;
        }

        _showRealityCheckModal();
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // MODAL RENDERING
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    function _showRealityCheckModal() {
        // Remove any existing modal
        const existing = document.getElementById('realityCheckModal');
        if (existing) existing.remove();

        // Calculate session stats
        const now = Date.now();
        const sessionMinutes = Math.floor((now - sessionData.startTime) / 60000);
        const currentBalance = typeof balance !== 'undefined' ? balance : 0;
        const netWinLoss = currentBalance - sessionData.startBalance;
        const averageBet = sessionData.spins > 0 ?
            (sessionData.totalWagered / sessionData.spins) : 0;

        // Create modal HTML
        const modalHTML = `
            <div id="realityCheckModal" class="reality-check-overlay">
                <div class="reality-check-modal">
                    <div class="reality-check-header">
                        <h2>â¸ Reality Check</h2>
                        <p class="reality-check-subtitle">You've been playing for <strong>${sessionMinutes}</strong> minute${sessionMinutes !== 1 ? 's' : ''}</p>
                    </div>

                    <div class="reality-check-stats">
                        <div class="reality-check-stat-group">
                            <div class="reality-check-stat">
                                <span class="reality-check-stat-label">Session Time</span>
                                <span class="reality-check-stat-value">${_formatTime(sessionMinutes)}</span>
                            </div>
                            <div class="reality-check-stat">
                                <span class="reality-check-stat-label">Total Spins</span>
                                <span class="reality-check-stat-value">${sessionData.spins}</span>
                            </div>
                        </div>

                        <div class="reality-check-stat-group">
                            <div class="reality-check-stat">
                                <span class="reality-check-stat-label">Total Wagered</span>
                                <span class="reality-check-stat-value">$${sessionData.totalWagered.toFixed(2)}</span>
                            </div>
                            <div class="reality-check-stat">
                                <span class="reality-check-stat-label">Average Bet</span>
                                <span class="reality-check-stat-value">$${averageBet.toFixed(2)}</span>
                            </div>
                        </div>

                        <div class="reality-check-stat-group">
                            <div class="reality-check-stat">
                                <span class="reality-check-stat-label">Total Won</span>
                                <span class="reality-check-stat-value">$${sessionData.totalWon.toFixed(2)}</span>
                            </div>
                            <div class="reality-check-stat ${netWinLoss < 0 ? 'negative' : 'positive'}">
                                <span class="reality-check-stat-label">Net Win/Loss</span>
                                <span class="reality-check-stat-value">${netWinLoss >= 0 ? '+' : ''}$${netWinLoss.toFixed(2)}</span>
                            </div>
                        </div>

                        <div class="reality-check-balance-row">
                            <div class="reality-check-balance">
                                <span class="reality-check-balance-label">Session Start Balance</span>
                                <span class="reality-check-balance-value">$${sessionData.startBalance.toFixed(2)}</span>
                            </div>
                            <div class="reality-check-balance">
                                <span class="reality-check-balance-label">Current Balance</span>
                                <span class="reality-check-balance-value">$${currentBalance.toFixed(2)}</span>
                            </div>
                        </div>
                    </div>

                    <div class="reality-check-message">
                        <p>Please take a moment to review your session. Gambling should always be fun and within your means.</p>
                    </div>

                    <div class="reality-check-buttons">
                        <button id="realityCheckContinue" class="reality-check-btn btn-continue">
                            Continue Playing
                        </button>
                        <button id="realityCheckBreak" class="reality-check-btn btn-break">
                            Take a Break
                        </button>
                    </div>
                </div>
            </div>
        `;

        // Insert modal into DOM
        document.body.insertAdjacentHTML('beforeend', modalHTML);

        // Wire up button handlers
        document.getElementById('realityCheckContinue').addEventListener('click', _handleContinue);
        document.getElementById('realityCheckBreak').addEventListener('click', _handleBreak);

        console.warn('[RealityCheck] Modal displayed');
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // MODAL ACTIONS
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    function _handleContinue() {
        const modal = document.getElementById('realityCheckModal');
        if (modal) modal.remove();

        // Resume game
        window.spinPausedForRealityCheck = false;

        // Restore auto-spin if it was paused
        if (sessionData.pausedAutoSpin && typeof autoSpinActive !== 'undefined') {
            autoSpinActive = true;
            sessionData.pausedAutoSpin = false;
            console.warn('[RealityCheck] Auto-spin resumed');
        }

        // Restart timer for next check
        const savedInterval = localStorage.getItem(STORAGE_KEY_INTERVAL);
        const minutes = savedInterval ? parseInt(savedInterval, 10) : DEFAULT_INTERVAL_MINUTES;
        _startTimer(minutes);

        console.warn('[RealityCheck] Player continued playing');
    }

    function _handleBreak() {
        const modal = document.getElementById('realityCheckModal');
        if (modal) modal.remove();

        window.spinPausedForRealityCheck = false;

        console.warn('[RealityCheck] Player took a break');

        // Attempt to return to lobby or logout
        // Check for common functions in the app
        if (typeof returnToLobby === 'function') {
            returnToLobby();
        } else if (typeof goToLobby === 'function') {
            goToLobby();
        } else if (typeof logout === 'function') {
            logout();
        } else {
            // Fallback: navigate to index
            window.location.href = '/';
        }
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // UTILITY FUNCTIONS
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    function _formatTime(minutes) {
        const hours = Math.floor(minutes / 60);
        const mins = minutes % 60;

        if (hours > 0) {
            return hours + 'h ' + mins + 'm';
        } else {
            return mins + 'm';
        }
    }

    function showNow() {
        // SLOT-ACTIVE GUARD: defer reality check until after slot closes
        var _sm = document.getElementById('slotModal'); if (_sm && _sm.classList.contains('active')) { setTimeout(showNow, 10000); return; }
        if (!initialized) {
            console.warn('[RealityCheck] Not initialized. Call init() first.');
            return;
        }

        _pauseGameAndShowModal();
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // PUBLIC API
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

    return {
        init: init,
        setInterval: setInterval,
        showNow: showNow
    };

})();

